WITH payload AS (
  SELECT $RISQQ21${"questions":[{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.18","internal_question_no":"03A.018","question_sort_key":3101800.032,"question_text":"Is the ECDIS of an approved type, compliant with SOLAS requirements, and can the Master and watch keeping officers demonstrate familiarity with its use?","guide_to_inspection":"Where an ECDIS is being used to meet the chart carriage requirements of SOLAS, it must:\n> Be type approved.\n> Use up-to-date electronic nautical charts (ENC);\n> Be maintained so as to be compatible with the latest applicable International Hydrographic Organisation (IHO) standards;\nand\n> Have adequate, independent back-up arrangements in place.\nAccording to SOLAS regulation V/18, ECDIS units on board ships must be type approved. Type approval is the certification\nprocess that ECDIS equipment must undergo before it can be considered as complying with IMO performance standards.\nThe process is carried out by flag Administration-accredited type-approval organisations or marine classification societies\nin accordance with the relevant test standards developed by, inter alia, the International Electro- technical Commission (IEC)\n(e.g., IEC 61174).\n(MSC.1/Circ.1503/Rev.1, ECDIS – GUIDANCE FOR GOOD PRACTICE, 2017)\nInformation related to current standards and latest software related to ENC and ECDIS are available on the IHO web site.\nThe IHO has issued a new version of the ECDIS presentation library edition 4.0. There will be no need to run the IHO ENC/\nECDIS data presentation and performance checks on the ECDIS.\nThe inspector should check the version of the IHO Standards installed on the ECDIS to confirm it is current.\nSeveral ECDIS manufactures recommend having particular ECDIS spare parts on board.\nIf the ECDIS manufacturer handbook includes a list of spare parts that should be stored on board, it is critical that these parts\nbe available on board for replacement anytime they are required.\nThe Master and watch keepers should be able to demonstrate their competency with the operation of ECDIS. This can be\nestablished by requesting use of basic functionality of the ECDIS in the presence of the inspector. These functions may\ninclude:\n> Safety setting\n> Setting voyage plan\n> Checking voyage plan\n> Interrogating chart updates\n> ENC symbol identification\n> Manual position fixing (NP5012/NP232)\n> AIS and or Radar overlay if fitted\n> Understanding the limitations of operating in RCDS mode\n> Knowledge of SCAMIN and how it is displayed\n> Knowledge of CATZOCs\n> Familiarity of deck officers with contingency action in case of ECDIS failure.\n> Setting of safety frame/safety cone\n> Creating parallel index lines\n> Route checking and management of alarms\n> Handling unresolved ENC update errors","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":33,"source_page_end":33,"raw_source_text":"Is the ECDIS of an approved type, compliant with SOLAS requirements, and can the Master and watch\nkeeping officers demonstrate familiarity with its use? (V)\nGuide to Inspection\nWhere an ECDIS is being used to meet the chart carriage requirements of SOLAS, it must:\n> Be type approved.\n> Use up-to-date electronic nautical charts (ENC);\n> Be maintained so as to be compatible with the latest applicable International Hydrographic Organisation (IHO) standards;\nand\n> Have adequate, independent back-up arrangements in place.\nAccording to SOLAS regulation V/18, ECDIS units on board ships must be type approved. Type approval is the certification\nprocess that ECDIS equipment must undergo before it can be considered as complying with IMO performance standards.\nThe process is carried out by flag Administration-accredited type-approval organisations or marine classification societies\nin accordance with the relevant test standards developed by, inter alia, the International Electro- technical Commission (IEC)\n(e.g., IEC 61174).\n(MSC.1/Circ.1503/Rev.1, ECDIS – GUIDANCE FOR GOOD PRACTICE, 2017)\nInformation related to current standards and latest software related to ENC and ECDIS are available on the IHO web site.\nThe IHO has issued a new version of the ECDIS presentation library edition 4.0. There will be no need to run the IHO ENC/\nECDIS data presentation and performance checks on the ECDIS.\nThe inspector should check the version of the IHO Standards installed on the ECDIS to confirm it is current.\nSeveral ECDIS manufactures recommend having particular ECDIS spare parts on board.\nIf the ECDIS manufacturer handbook includes a list of spare parts that should be stored on board, it is critical that these parts\nbe available on board for replacement anytime they are required.\nThe Master and watch keepers should be able to demonstrate their competency with the operation of ECDIS. This can be\nestablished by requesting use of basic functionality of the ECDIS in the presence of the inspector. These functions may\ninclude:\n> Safety setting\n> Setting voyage plan\n> Checking voyage plan\n> Interrogating chart updates\n> ENC symbol identification\n> Manual position fixing (NP5012/NP232)\n> AIS and or Radar overlay if fitted\n> Understanding the limitations of operating in RCDS mode\n> Knowledge of SCAMIN and how it is displayed\n> Knowledge of CATZOCs\n> Familiarity of deck officers with contingency action in case of ECDIS failure.\n> Setting of safety frame/safety cone\n> Creating parallel index lines\n> Route checking and management of alarms\n> Handling unresolved ENC update errors","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.19","internal_question_no":"03A.019","question_sort_key":3101900.033,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":33,"source_page_end":33,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.20","internal_question_no":"03A.020","question_sort_key":3102000.034,"question_text":"Are T&P NMs and navigation warnings being used correctly in voyage planning and monitoring?","guide_to_inspection":"Some ECDIS have a feature to automatically import navigational warning from Sat-C or NAVTEX terminals. Navigation\nOfficers should verify that navigation warning information is currently displayed.\nSpecific details of a critical navigational warning should be plotted and made alarmable by using the look-ahead feature to\nhighlight the navigational hazard for the Officer of the Watch.\n(Recommendations on Usage of ECDIS and Preventing Incident, 2020)\nEnsure the vessel has access to all necessary T&P NM information and that this is documented.\nWhere relevant to the voyage plan, T&P corrections should be inserted on the ECDIS display using manual corrections. The\nADMIRALTY Information overlay (AIO) provides easy reference to T&P information; this can be displayed on a range of ECDIS\nor on back of bridge systems such as ADMIRALTY e-Navigator.\n(Admiralty Guide to ECDIS Implementation, Policy and Procedures, 2016)\nInspectors should check if the system is installed and verify if relevant notices are effectively managed.\nThe overlay is displayed as a single layer on top of the basic ENC. This ensures that users have the most up to date T&P\ninformation available regardless of where they are in the world.\nT&P NMs are delivered on a weekly basis on the update DVD or with the online/email updates, depending on requirements.\nThe information contained in the Overlay is important navigational information that should be used when planning a\nvoyage and may be referred to when navigating. The Admiralty Information Overlay contains all Admiralty T&P NMs in force\nworldwide and additional ENC P (EP) NMs, which relate specifically to ENCs. (Admiralty Guide to ECDIS Implementation,\nPolicy and Procedures, 2016)\nNavigation officer should not entirely rely on AIO as they may not be updated, and applicable T&P notices should be verified\nagainst weekly notices to mariners.\n(Recommendations on Usage of ECDIS and Preventing Incident, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":33,"source_page_end":34,"raw_source_text":"Are T&P NMs and navigation warnings being used correctly in voyage planning and monitoring? (V)\nGuide to Inspection\nSome ECDIS have a feature to automatically import navigational warning from Sat-C or NAVTEX terminals. Navigation\nOfficers should verify that navigation warning information is currently displayed.\nSpecific details of a critical navigational warning should be plotted and made alarmable by using the look-ahead feature to\nhighlight the navigational hazard for the Officer of the Watch.\n(Recommendations on Usage of ECDIS and Preventing Incident, 2020)\nEnsure the vessel has access to all necessary T&P NM information and that this is documented.\nWhere relevant to the voyage plan, T&P corrections should be inserted on the ECDIS display using manual corrections. The\nADMIRALTY Information overlay (AIO) provides easy reference to T&P information; this can be displayed on a range of ECDIS\nor on back of bridge systems such as ADMIRALTY e-Navigator.\n(Admiralty Guide to ECDIS Implementation, Policy and Procedures, 2016)\nInspectors should check if the system is installed and verify if relevant notices are effectively managed.\nThe overlay is displayed as a single layer on top of the basic ENC. This ensures that users have the most up to date T&P\ninformation available regardless of where they are in the world.\nT&P NMs are delivered on a weekly basis on the update DVD or with the online/email updates, depending on requirements.\nThe information contained in the Overlay is important navigational information that should be used when planning a\nvoyage and may be referred to when navigating. The Admiralty Information Overlay contains all Admiralty T&P NMs in force\nworldwide and additional ENC P (EP) NMs, which relate specifically to ENCs. (Admiralty Guide to ECDIS Implementation,\nPolicy and Procedures, 2016)\nNavigation officer should not entirely rely on AIO as they may not be updated, and applicable T&P notices should be verified\nagainst weekly notices to mariners.\n(Recommendations on Usage of ECDIS and Preventing Incident, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.21","internal_question_no":"03A.021","question_sort_key":3102100.035,"question_text":"Has the vessel been safely navigated in compliance with international and inland regulations?","guide_to_inspection":"ENC’s/Charts of the last voyage should be checked by the inspector to assess whether the vessel has been safely navigated.\nThe inspector shall consider following when assessing the last voyage charts:\n> Largest scale charts to be available with route plotted.\n> Record of weather forecast.\n> Appropriate measures to be taken to comply with environmental requirements and regulations.\n> Safety and alarm setting of ECDIS.\n> Maintenance of safe distance off the coast, from prohibited area and dangerous wrecks.\n> Adequate bridge manning to ensure a proper look-out.\n> Ship’s position confirmation at appropriate intervals.\n> Weather monitoring by making regular barometer observations.\n> NAVAREA navigational warning broadcasts where applicable checked.\n> Participation in area reporting systems; and\n> Gyro and magnetic compass errors and radar performance checked properly.\n> Correct minimum layers of ECDIS according to the company SMS.\nIf an appropriate safety contour is not available on the ENC, a manual alarmable contour should be drawn as a manual layer\non the ENC that should always be selected and displayed during the passage.\n(Recommendations on Usage of ECDIS and Preventing Incident, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":34,"source_page_end":34,"raw_source_text":"Has the vessel been safely navigated in compliance with international and inland regulations? (V)\nGuide to Inspection\nENC’s/Charts of the last voyage should be checked by the inspector to assess whether the vessel has been safely navigated.\nThe inspector shall consider following when assessing the last voyage charts:\n> Largest scale charts to be available with route plotted.\n> Record of weather forecast.\n> Appropriate measures to be taken to comply with environmental requirements and regulations.\n> Safety and alarm setting of ECDIS.\n> Maintenance of safe distance off the coast, from prohibited area and dangerous wrecks.\n> Adequate bridge manning to ensure a proper look-out.\n> Ship’s position confirmation at appropriate intervals.\n> Weather monitoring by making regular barometer observations.\n> NAVAREA navigational warning broadcasts where applicable checked.\n> Participation in area reporting systems; and\n> Gyro and magnetic compass errors and radar performance checked properly.\n> Correct minimum layers of ECDIS according to the company SMS.\nIf an appropriate safety contour is not available on the ENC, a manual alarmable contour should be drawn as a manual layer\non the ENC that should always be selected and displayed during the passage.\n(Recommendations on Usage of ECDIS and Preventing Incident, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.22","internal_question_no":"03A.022","question_sort_key":3102200.036,"question_text":"Are records available to show that the echo-sounder recorder is being switched on prior to each approach to shallow water, port entry and departure and has the echo sounder remained in operation while the vessel has been transiting in shallow waters?","guide_to_inspection":"The echo sounder should always be used when making a landfall and kept switched on in coastal and pilotage waters. If the echo\nsounder is fitted with a shallow water alarm, the alarm should be set to an appropriate safe depth to warn of approaching shallow\nwater. t is important to check the units of soundings on the echo sounder are the same as those on the chart in use.\nThe depth alarm on the echo sounder should not be set to a value lower than the ship’s sailing draft.\n(Bridge Procedures Guide, 2022)\nThe date and time of switching on should be marked on the recorder chart.\nThe echo sounders may have an internal memory and record data from the past 24 hours, in which case the recorder is not\nrequired.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":34,"source_page_end":34,"raw_source_text":"Are records available to show that the echo-sounder recorder is being switched on prior to each approach\nto shallow water, port entry and departure and has the echo sounder remained in operation while the vessel\nhas been transiting in shallow waters? (V)\nGuide to Inspection\nThe echo sounder should always be used when making a landfall and kept switched on in coastal and pilotage waters. If the echo\nsounder is fitted with a shallow water alarm, the alarm should be set to an appropriate safe depth to warn of approaching shallow\nwater. t is important to check the units of soundings on the echo sounder are the same as those on the chart in use.\nThe depth alarm on the echo sounder should not be set to a value lower than the ship’s sailing draft.\n(Bridge Procedures Guide, 2022)\nThe date and time of switching on should be marked on the recorder chart.\nThe echo sounders may have an internal memory and record data from the past 24 hours, in which case the recorder is not\nrequired.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.23","internal_question_no":"03A.023","question_sort_key":3102300.037,"question_text":"Was the berth-to-berth passage plan of the previous voyage comprehensive and approved by the Master?","guide_to_inspection":"To comply with the international, local regulations and industry recommendations, the vessel manager should establish a\nprocedure for onboard officers to appraise, plan, execute and monitor every passage berth to berth including anchorage.\nThe format of the passage plan should include, but not be limited to, the minimum information that must be included:\n> Parallel indexing: Parallel indexing should not be performed from floating objects unless they have first been checked\nfor position.\n> Chart changes.\n> Methods and frequency of position fixing and/or position verification.\n> Prominent navigation and radar marks.\n> No-go areas.\n> Landfall targets and lights.\n> Clearing lines and bearings.\n> Transits, heading marks and leading lines.\n> Significant tides or current.\n> Safe speed and necessary speed alterations.\n> Changes in machinery space status, i.e. manned/unmanned.\n> Changes in machinery status, i.e. standby for manoeuvring.\n> Changes in bridge watch composition.\n> Changes to fuel and/or scrubber use.\n> Changes in security arrangements.\n> Minimum under keel clearance.\n> Positions where the echo sounder should be activated.\n> Crossing and high-density traffic areas.\n> Safe distance off navigational hazards or marks.\n> Anchor clearance.\n> Contingency plans.\n> Abort positions.\n> VTS and reporting points.\n> Air draft when passing under a bridge or object.\n> Alternative or contingency routing that may be required at short notice.\n> Specific guidance provided by local routing publications where applicable to the vessel and its route.\n> The process to verify that all navigational and environmental considerations have been included in the final passage plan.\n> The review and approval process for a passage plan including utilising the ECDIS route checking function.\n> The record keeping requirements as they relate to the progress of the passage and navigational events.\n> The actions to take to update the passage plan when circumstances change requiring the vessel to deviate from the\noriginally agreed plan.\n> The requirement for preparing the passage plan on both paper charts and ECDIS where the vessel has a single ECDIS\nunit or has nominated paper charts as the primary means of navigation.\n> The requirement for a passage plan briefing including the Master, all navigation officers, and a representative from the\nengineering department.\n> A vessel should deviate from its planned passage to extend necessary to safely comply with the collision regulations.\nTherefore, it is important to carefully consider these factors when evaluating the passage and creating a plan to ensure\nsufficient sea room and suitable watch condition.\nWhen using ECDIS for passage planning, the following factors should be considered:\n> Availability of and access to the required up-to date ENCs and RNCs for the intended passage. This should include\nidentification of areas where ECDIS may need to be in raster chart display system (RCDC) mode and where paper charts\nmight therefore be required;\n> If reusing a previous passage plan, the need to recheck the route to confirm that it remains safe and no changes are\nnecessary;\n> An appropriate large scale ENC or RNC should be used when planning a route;\n> Making sure that any old or previous routes are removed from the display;\n> The need to select chart symbols(pick report) on ENCs to get additional detailed safety and navigational information;\n> Applying a maximum acceptable cross track distance (XTD)to each leg of a route. This should comply with any requirements\nin the SMS and be appropriate for the area;\n> Calculating safety depths and safety contour and setting them up in line with the under keel clearance(UKC) requirements in\nthe SMS;\n> Setting estimated time of arrival(ETA) information manually or using route planning tools. If this is set incorrectly, it may affect\ntidal data and time dependent information for the route;\n> Applying current and tidal data, if integrated with ECDIS and up to date, to the route; and\n> Checking information about the vessel’s characteristics and confirming it as correct. This includes details about draft\n(including any allowance for squat or additional safety margins),turn radius and vessel dimensions;\n> The passage plan should be saved, backed up and locked to prevent unauthorised editing.\n> The Master should check and approve the passage plan. The person responsible for the passage plan shall brief the bridge\nteam. This must all be documented in accordance with Bridge Procedures Guide check list C.2.9.\nThe shallow contour value must be equal to or more than the lowest draft of the ship.\nThe officer of watch shall consider following when calculating the safety contour:\n> The ship’s sailing draft and trim\n> Expected squat or allowance for squat\n> UKC as per company SMS\n> Expected height of tide\n>\nBy setting a safety depth, spot soundings are highlighted in grey (deep waters) or black(shallow waters) when compared with the\nsafety depth value entered by the OOW.\n-In calculating the ship’s safety depth, it is also important to consider the category zone of confidence (CATZOC) value of the chart\nin use.\n(Bridge Procedures ,2022)\nRoute validation is a critical aspect of a passage plan. The route validation involves the following stages:\n> Visual checks\n> Manual and auto-validation features\n> Cross-checks by the bridge team\n> Final validation and authorisation by the Master\n> Re-validation along the route.\n>\nThe Master should only authorise the plan once all stages of visual check and route validation have been completed.\n(Recommendations on Usage of ECDIS and Preventing Incident, 2020)\nThe route validation check of previous voyage should be documented and reviewed by inspector.\nA list of ENCs used for the intended voyage should be part of passage plan. The parameters for the look-ahead zone should be\nplanned so that the size of the zone is appropriate for the vessel’s speed and manoeuvring characteristics. They should be set for\neach leg of the passage and should consider conditions such as proceeding from ocean to coastal waters, pilotage areas or speed.\nThe look-ahead zone should be reassessed in CATZOC area that have reduced position accuracy (such as B, C, D, U) to ensure the\nvessel has a sufficient safety margin.\nAmendment to the passage plan should be officially documented and specific changes recorded on the passage plan form,\naccording to company SMS.\nAlarm-setting parameters should be agreed by the Master and bridge team at the passage planning stage and captured in\nthe relevant passage plan form.\n(Recommendations on Usage of ECDIS and Preventing Incident, 2020)\nThe following marine environmental factors shall be taken into account during an appraisal of the passage plan:\n> Ballast water management\n> Emission Control Areas (ECA)\n> MARPOL Special Areas\n> National or regional requirements\n> Particularly Sensitive Sea area(PSSA)\n> Garbage disposal\n> Port reception facility\n( Bridge Procedures Guide , 2022)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":35,"source_page_end":36,"raw_source_text":"Was the berth-to-berth passage plan of the previous voyage comprehensive and approved by the Master? (V)\nGuide to Inspection\nTo comply with the international, local regulations and industry recommendations, the vessel manager should establish a\nprocedure for onboard officers to appraise, plan, execute and monitor every passage berth to berth including anchorage.\nThe format of the passage plan should include, but not be limited to, the minimum information that must be included:\n> Parallel indexing: Parallel indexing should not be performed from floating objects unless they have first been checked\nfor position.\n> Chart changes.\n> Methods and frequency of position fixing and/or position verification.\n> Prominent navigation and radar marks.\n> No-go areas.\n> Landfall targets and lights.\n> Clearing lines and bearings.\n> Transits, heading marks and leading lines.\n> Significant tides or current.\n> Safe speed and necessary speed alterations.\n> Changes in machinery space status, i.e. manned/unmanned.\n> Changes in machinery status, i.e. standby for manoeuvring.\n> Changes in bridge watch composition.\n> Changes to fuel and/or scrubber use.\n> Changes in security arrangements.\n> Minimum under keel clearance.\n> Positions where the echo sounder should be activated.\n> Crossing and high-density traffic areas.\n> Safe distance off navigational hazards or marks.\n> Anchor clearance.\n> Contingency plans.\n> Abort positions.\n> VTS and reporting points.\n> Air draft when passing under a bridge or object.\n> Alternative or contingency routing that may be required at short notice.\n> Specific guidance provided by local routing publications where applicable to the vessel and its route.\n> The process to verify that all navigational and environmental considerations have been included in the final passage plan.\n> The review and approval process for a passage plan including utilising the ECDIS route checking function.\n> The record keeping requirements as they relate to the progress of the passage and navigational events.\n> The actions to take to update the passage plan when circumstances change requiring the vessel to deviate from the\noriginally agreed plan.\n> The requirement for preparing the passage plan on both paper charts and ECDIS where the vessel has a single ECDIS\nunit or has nominated paper charts as the primary means of navigation.\n> The requirement for a passage plan briefing including the Master, all navigation officers, and a representative from the\nengineering department.\n> A vessel should deviate from its planned passage to extend necessary to safely comply with the collision regulations.\nTherefore, it is important to carefully consider these factors when evaluating the passage and creating a plan to ensure\nsufficient sea room and suitable watch condition.\nWhen using ECDIS for passage planning, the following factors should be considered:\n> Availability of and access to the required up-to date ENCs and RNCs for the intended passage. This should include\nidentification of areas where ECDIS may need to be in raster chart display system (RCDC) mode and where paper charts\nmight therefore be required;\n> If reusing a previous passage plan, the need to recheck the route to confirm that it remains safe and no changes are\nnecessary;\n> An appropriate large scale ENC or RNC should be used when planning a route;\n> Making sure that any old or previous routes are removed from the display;\n> The need to select chart symbols(pick report) on ENCs to get additional detailed safety and navigational information;\n> Applying a maximum acceptable cross track distance (XTD)to each leg of a route. This should comply with any requirements\nin the SMS and be appropriate for the area;\n> Calculating safety depths and safety contour and setting them up in line with the under keel clearance(UKC) requirements in\nthe SMS;\n> Setting estimated time of arrival(ETA) information manually or using route planning tools. If this is set incorrectly, it may affect\ntidal data and time dependent information for the route;\n> Applying current and tidal data, if integrated with ECDIS and up to date, to the route; and\n> Checking information about the vessel’s characteristics and confirming it as correct. This includes details about draft\n(including any allowance for squat or additional safety margins),turn radius and vessel dimensions;\n> The passage plan should be saved, backed up and locked to prevent unauthorised editing.\n> The Master should check and approve the passage plan. The person responsible for the passage plan shall brief the bridge\nteam. This must all be documented in accordance with Bridge Procedures Guide check list C.2.9.\nThe shallow contour value must be equal to or more than the lowest draft of the ship.\nThe officer of watch shall consider following when calculating the safety contour:\n> The ship’s sailing draft and trim\n> Expected squat or allowance for squat\n> UKC as per company SMS\n> Expected height of tide\n>\nBy setting a safety depth, spot soundings are highlighted in grey (deep waters) or black(shallow waters) when compared with the\nsafety depth value entered by the OOW.\n-In calculating the ship’s safety depth, it is also important to consider the category zone of confidence (CATZOC) value of the chart\nin use.\n(Bridge Procedures ,2022)\nRoute validation is a critical aspect of a passage plan. The route validation involves the following stages:\n> Visual checks\n> Manual and auto-validation features\n> Cross-checks by the bridge team\n> Final validation and authorisation by the Master\n> Re-validation along the route.\n>\nThe Master should only authorise the plan once all stages of visual check and route validation have been completed.\n(Recommendations on Usage of ECDIS and Preventing Incident, 2020)\nThe route validation check of previous voyage should be documented and reviewed by inspector.\nA list of ENCs used for the intended voyage should be part of passage plan. The parameters for the look-ahead zone should be\nplanned so that the size of the zone is appropriate for the vessel’s speed and manoeuvring characteristics. They should be set for\neach leg of the passage and should consider conditions such as proceeding from ocean to coastal waters, pilotage areas or speed.\nThe look-ahead zone should be reassessed in CATZOC area that have reduced position accuracy (such as B, C, D, U) to ensure the\nvessel has a sufficient safety margin.\nAmendment to the passage plan should be officially documented and specific changes recorded on the passage plan form,\naccording to company SMS.\nAlarm-setting parameters should be agreed by the Master and bridge team at the passage planning stage and captured in\nthe relevant passage plan form.\n(Recommendations on Usage of ECDIS and Preventing Incident, 2020)\nThe following marine environmental factors shall be taken into account during an appraisal of the passage plan:\n> Ballast water management\n> Emission Control Areas (ECA)\n> MARPOL Special Areas\n> National or regional requirements\n> Particularly Sensitive Sea area(PSSA)\n> Garbage disposal\n> Port reception facility\n( Bridge Procedures Guide , 2022)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.24","internal_question_no":"03A.024","question_sort_key":3102400.038,"question_text":"Was the ship’s track monitored at sea and during pilotage, and were parallel indexing techniques used to monitor the passage in coastal and pilotage waters ,particularly during restricted visibility or nighttime conditions?","guide_to_inspection":"Radar overlays should be used for position verification at regular interval, as defined by company SMS requirements, and for\nvarious navigation conditions such as in open waters, confined waters, fairways/channels, or pilotage waters.\nPosition plotting should also be undertaken using traditional techniques, using lines of position to plot visual /radar fixes.\nThis will act as a cross check and will be recorded on the ECDIS data log. (Recommendations on Usage of ECDIS and\nPreventing Incident, 2020)\nCompliance with the passage plan should be closely monitored by the OOW:\n> To check that the ship’s position is maintained within an authorized XTD, including following alterations of course to\n> avoid collision or following a planned course alteration;\n> By fixing the ship’s position at the frequency based on existing conditions and the proximity of navigational hazards;\n> By cross checking the ship’s position using all appropriate means including;\n> By visual and/or radar fixing techniques using ranges and bearing of charted objects;\n> By echo sounder to monitor charted depths and contours; and\n> By monitoring the integrity of information displayed on navigation equipment.\n(Bridge Procedures Guide, 2022)\nThe following techniques should be used when monitoring the passage in coastal and pilotage waters, particularly in\nconditions of restricted visibility or at night:\n> Parallel indexing, which is recommended to ensure the ship’s track is maintained.\n> Radar bearings; and\n> Radar ranges.\n(Bridge Procedures Guide, 2022)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":36,"source_page_end":36,"raw_source_text":"Was the ship’s track monitored at sea and during pilotage, and were parallel indexing techniques used to\nmonitor the passage in coastal and pilotage waters ,particularly during restricted visibility or nighttime conditions? (V)\nGuide to Inspection\nRadar overlays should be used for position verification at regular interval, as defined by company SMS requirements, and for\nvarious navigation conditions such as in open waters, confined waters, fairways/channels, or pilotage waters.\nPosition plotting should also be undertaken using traditional techniques, using lines of position to plot visual /radar fixes.\nThis will act as a cross check and will be recorded on the ECDIS data log. (Recommendations on Usage of ECDIS and\nPreventing Incident, 2020)\nCompliance with the passage plan should be closely monitored by the OOW:\n> To check that the ship’s position is maintained within an authorized XTD, including following alterations of course to\n> avoid collision or following a planned course alteration;\n> By fixing the ship’s position at the frequency based on existing conditions and the proximity of navigational hazards;\n> By cross checking the ship’s position using all appropriate means including;\n> By visual and/or radar fixing techniques using ranges and bearing of charted objects;\n> By echo sounder to monitor charted depths and contours; and\n> By monitoring the integrity of information displayed on navigation equipment.\n(Bridge Procedures Guide, 2022)\nThe following techniques should be used when monitoring the passage in coastal and pilotage waters, particularly in\nconditions of restricted visibility or at night:\n> Parallel indexing, which is recommended to ensure the ship’s track is maintained.\n> Radar bearings; and\n> Radar ranges.\n(Bridge Procedures Guide, 2022)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.25","internal_question_no":"03A.025","question_sort_key":3102500.039,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":37,"source_page_end":37,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.26","internal_question_no":"03A.026","question_sort_key":3102600.04,"question_text":"Is the Global Navigation Satellite System (GNSS) set to the correct Geodetic Datum, and are officers aware of the errors and alarms associated with GNSS?","guide_to_inspection":"A GNSS is a satellite-based system that provides continuous worldwide position, time and speed(over ground) information. Two\nsystems that give near global coverage are available to ships:\n> Global Positioning system (GPS) operated by the United States; and\n> Global Navigation Satellite System (GLONASS) operated by the Russian Federation.\nOther satellite systems recognized as components of the World-Wide Radio Navigation System (WWRNS) are:\n> BeiDou Navigation Satellite System (BDS) operated by China; and\n> Galileo Global Satellite System (Galileo) operated by the EU.\nGNSS generally have a based accuracy in the order of 15-25 meters. Differential GNSS receivers offers greater navigational accuracy\nby applying corrections received from ground based reference stations.\nThe OOW should be familiar with the GNSS system used on board.\nThe GNSS system should indicate its current operating status and any associated alarms or errors.\nSome common errors are:\nDilution of precision error (DOP): This error occur when fewer satellites are available to the ship. It is common when sailing in area with\nhigh mountains such as Alaska or Norway.\nReceiver autonomous integrity monitoring (RAIM): This error relates to the quality of the data being sent to the GNSS receiver. If the\nsystem detects a drop in quality, it will alert the user.\nGNSS jamming or spoofing: This can happen in an area of increased military presence. The OOW may notice a position jump on ECDIS\nor, when cross- checking position, the GNSS position may be unreliable.\nMulti path error: Similar to the DOP error. The GNSS receiver may be blocked or receiving a double signal. This could be due to\ninterference by structure, mountains, etc.\n-ENCs use WGS 84 as the geodetic datum. Many GNSS receivers have internal facilities to transform positions between different\ngeodetic datum, eliminating the need to apply datum offsets manually.\n( Bridge Procedures Guide, 2022)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":37,"source_page_end":37,"raw_source_text":"Is the Global Navigation Satellite System (GNSS) set to the correct Geodetic Datum, and are officers aware\nof the errors and alarms associated with GNSS?\nGuide to Inspection\nA GNSS is a satellite-based system that provides continuous worldwide position, time and speed(over ground) information. Two\nsystems that give near global coverage are available to ships:\n> Global Positioning system (GPS) operated by the United States; and\n> Global Navigation Satellite System (GLONASS) operated by the Russian Federation.\nOther satellite systems recognized as components of the World-Wide Radio Navigation System (WWRNS) are:\n> BeiDou Navigation Satellite System (BDS) operated by China; and\n> Galileo Global Satellite System (Galileo) operated by the EU.\nGNSS generally have a based accuracy in the order of 15-25 meters. Differential GNSS receivers offers greater navigational accuracy\nby applying corrections received from ground based reference stations.\nThe OOW should be familiar with the GNSS system used on board.\nThe GNSS system should indicate its current operating status and any associated alarms or errors.\nSome common errors are:\nDilution of precision error (DOP): This error occur when fewer satellites are available to the ship. It is common when sailing in area with\nhigh mountains such as Alaska or Norway.\nReceiver autonomous integrity monitoring (RAIM): This error relates to the quality of the data being sent to the GNSS receiver. If the\nsystem detects a drop in quality, it will alert the user.\nGNSS jamming or spoofing: This can happen in an area of increased military presence. The OOW may notice a position jump on ECDIS\nor, when cross- checking position, the GNSS position may be unreliable.\nMulti path error: Similar to the DOP error. The GNSS receiver may be blocked or receiving a double signal. This could be due to\ninterference by structure, mountains, etc.\n-ENCs use WGS 84 as the geodetic datum. Many GNSS receivers have internal facilities to transform positions between different\ngeodetic datum, eliminating the need to apply datum offsets manually.\n( Bridge Procedures Guide, 2022)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.27","internal_question_no":"03A.027","question_sort_key":3102700.041,"question_text":"Does the vessel utilise a weather routeing service?","guide_to_inspection":"Weather routeing allows the Master and the bridge team to follow a passage plan that avoids the worst weather in the interest of\nsafety and fuel consumption efficiency.\nWeather routeing predicts the movement of weather systems associated with poor conditions and rough seas. The most favorable\nroute is then planned, taking these systems into consideration.\nThe main benefits of weather routeing are:\n> Increase safety;\n> Better conditions for cargo or passengers\n> Fuel and time saving; and\n> Reduced costs overall\nWeather routeing is an aid to navigation and the Master should always consider routeing information as well as applying good\nseamanship.\nThe safety of the ship, its crew and its cargo or its passengers should always have priority over the ETA.\nThe bridge team should be familiar with dedicated software for weather routeing on board.\n(Bridge Procedures Guide ,2022)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":37,"source_page_end":37,"raw_source_text":"Does the vessel utilise a weather routeing service? (V)\nGuide to Inspection\nWeather routeing allows the Master and the bridge team to follow a passage plan that avoids the worst weather in the interest of\nsafety and fuel consumption efficiency.\nWeather routeing predicts the movement of weather systems associated with poor conditions and rough seas. The most favorable\nroute is then planned, taking these systems into consideration.\nThe main benefits of weather routeing are:\n> Increase safety;\n> Better conditions for cargo or passengers\n> Fuel and time saving; and\n> Reduced costs overall\nWeather routeing is an aid to navigation and the Master should always consider routeing information as well as applying good\nseamanship.\nThe safety of the ship, its crew and its cargo or its passengers should always have priority over the ETA.\nThe bridge team should be familiar with dedicated software for weather routeing on board.\n(Bridge Procedures Guide ,2022)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.28","internal_question_no":"03A.028","question_sort_key":3102800.042,"question_text":"Are there procedures in place to limit the use of cell phones, personal electronic devices, the internet, and email on the bridge?","guide_to_inspection":"A quiet bridge to allow VHF radio calls and sound signals to be heard.\nThe company should have a written policy requiring that mobile phones or other personal electronic devices should only be used\non the bridge in circumstances approved by the Master. While on some occasions the use of mobile phones or personal electronic\ndevices may be permitted, the company policy should minimise the distraction resulting from such devices by, in general, limiting\ntheir use to operationally necessary circumstances.\nWhere internet and email services are available on the bridge, the Company should have a policy to manage their use. Access to\ninternet and email use by bridge watch keepers should generally be limited to those circumstances where it is necessary for the\nsafe navigation of the ship, in order to minimise distraction that might be caused to the Bridge Team.\nInternet access and email on the bridge should usually be restricted to:\n> Updates for nautical charts and publications, licences and permits.\n> Weather information.\n> Navigational warnings; and\n> Information relevant to the ship’s operations and passage plan.\n(Bridge Procedures Guide, 2022)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":38,"source_page_end":38,"raw_source_text":"Are there procedures in place to limit the use of cell phones, personal electronic devices, the internet, and\nemail on the bridge?\nGuide to Inspection\nA quiet bridge to allow VHF radio calls and sound signals to be heard.\nThe company should have a written policy requiring that mobile phones or other personal electronic devices should only be used\non the bridge in circumstances approved by the Master. While on some occasions the use of mobile phones or personal electronic\ndevices may be permitted, the company policy should minimise the distraction resulting from such devices by, in general, limiting\ntheir use to operationally necessary circumstances.\nWhere internet and email services are available on the bridge, the Company should have a policy to manage their use. Access to\ninternet and email use by bridge watch keepers should generally be limited to those circumstances where it is necessary for the\nsafe navigation of the ship, in order to minimise distraction that might be caused to the Bridge Team.\nInternet access and email on the bridge should usually be restricted to:\n> Updates for nautical charts and publications, licences and permits.\n> Weather information.\n> Navigational warnings; and\n> Information relevant to the ship’s operations and passage plan.\n(Bridge Procedures Guide, 2022)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.1","internal_question_no":"04A.001","question_sort_key":4100100.043,"question_text":"Has the vessel’s manager established a documented system for personnel to effectively implement the ISM Code?","guide_to_inspection":"The latest revision of ISM manuals, procedure and instructions should be available. The inspector shall examine the\ncompliance of the vessel with the procedures and instruction during the course of inspection\nThe company should define and document the responsibility, authority, and interrelation of all personnel who manager,\nperform and verify work relating to and affecting safety and pollution prevention.\nThe company should establish procedures, plans and instructions, including checklists as appropriate, for key shipboard\noperations concerning the safety of the personnel and, ship and protection of the environment. The various tasks should be\ndefined and assigned to qualified personnel.\n(ISM code and guidelines on the implementation of the ISM code, 2018)\nThe documents used to define and implement the SMS may be described as the Safety Management Manual. It may be more\nthan one manual and may take the form that the company considers most appropriate. Policies, practices, and procedures\nare to be followed in order to ensure safe functioning of ships at sea.\nA list of on-board publications shall be incorporated in SMS. A Finding should be filed by the inspector against ships not\ncarrying publications in accordance with National requirements and the SMS.\nCarrying solid bulk cargoes involves significant risks that must be carefully managed to protect the crew and the ship. These\nrisks include reduced ship stability, and possibly capsize, as a result of cargo liquefaction; fire or explosion as a result of\nchemical hazards; and structural damage to ships as a result of incorrect loading procedures.\nCarrying grain cargoes involves significant risks that must be carefully managed to protect the crew and the ship. These\ndangers include settling, shifting, contamination, dust explosions, and fire, as well as rotting caused by ingress of water and\nsubsequent oxygen depletion or the evolution of toxic vapors.\nGeneral cargoes include industrial commodities, bagged cargoes, project cargoes, steel products, forest products, palletized\ncargoes, smaller break-bulk cargoes, automobiles, containers, heavy lifts, dangerous goods, and out-of-gauge cargoes.\nContainer cargo includes a number of risks for the crew, the ship, and the environment. Stowage, cargo securing, stability and\nstress calculations, dangerous goods segregation, mis-declared overweight containers, out of gauge containers, refrigerated\ncontainers, on deck and under deck stowage, half door or both door open containers, lashing strength, sailing conditions,\nvisibility, and heavy weather all pose risks to the ship, crew, and environment if not addressed properly.\nMSC-MEPC.2/Circ.2 of 1 June 2006, “IMO requirements on carriage of publications on board ships” provides the publications\nwhich are specifically required to be carried on board ships by IMO instruments.\nIMO instruments such as the SOLAS, MARPOL, LL, COLREG and STCW Conventions deal with many operational aspects,\ninter alia, navigational responsibilities, safety-related training/drills on board, safe cargo handling, oil spill prevention, collision\navoidance activities and watchkeeping standards.\nTherefore, these publications, although not expressly required by IMO instruments, may need to be carried on board to\nimprove the crew’s knowledge and to enhance the implementation of IMO instruments. No Finding should be filed by the\ninspector against ships not carrying such publications on board unless otherwise required by the ships Safety Management\nSystem manual.\n(IMO REQUIREMENTS ON CARRIAGE OF PUBLICATIONS ON BOARD SHIPS, 2006)\nWhen a vessel is a gravity-based self-unloading and/or hybrid self-unloading type discharging bulk cargo either onshore or\noffshore, the following should be included in the SMS:\n> Starting procedure\n> How to avoid overloading the self-unloading system\n> Stopover procedure –Prevent forging material that may in the cargo hold hopper gates and damage the belt\n> Selecting a variable speed and discharge rate\n> Electric and hydraulic controls\n> Hold discharge gate, conveyors, and elevator\n> Boom conveyor\n> Energy isolation permits and isolation/lock\n> Gate problems including:\n> Gate blockage\n> Gate off-track\n> Loss of gate power\n> Foreign object in way of a gate\n> Actuation of emergency stops\n> Cleaning procedure for the gates","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":39,"source_page_end":39,"raw_source_text":"Has the vessel’s manager established a documented system for personnel to effectively\nimplement the ISM Code? (V)\nGuide to Inspection\nThe latest revision of ISM manuals, procedure and instructions should be available. The inspector shall examine the\ncompliance of the vessel with the procedures and instruction during the course of inspection\nThe company should define and document the responsibility, authority, and interrelation of all personnel who manager,\nperform and verify work relating to and affecting safety and pollution prevention.\nThe company should establish procedures, plans and instructions, including checklists as appropriate, for key shipboard\noperations concerning the safety of the personnel and, ship and protection of the environment. The various tasks should be\ndefined and assigned to qualified personnel.\n(ISM code and guidelines on the implementation of the ISM code, 2018)\nThe documents used to define and implement the SMS may be described as the Safety Management Manual. It may be more\nthan one manual and may take the form that the company considers most appropriate. Policies, practices, and procedures\nare to be followed in order to ensure safe functioning of ships at sea.\nA list of on-board publications shall be incorporated in SMS. A Finding should be filed by the inspector against ships not\ncarrying publications in accordance with National requirements and the SMS.\nCarrying solid bulk cargoes involves significant risks that must be carefully managed to protect the crew and the ship. These\nrisks include reduced ship stability, and possibly capsize, as a result of cargo liquefaction; fire or explosion as a result of\nchemical hazards; and structural damage to ships as a result of incorrect loading procedures.\nCarrying grain cargoes involves significant risks that must be carefully managed to protect the crew and the ship. These\ndangers include settling, shifting, contamination, dust explosions, and fire, as well as rotting caused by ingress of water and\nsubsequent oxygen depletion or the evolution of toxic vapors.\nGeneral cargoes include industrial commodities, bagged cargoes, project cargoes, steel products, forest products, palletized\ncargoes, smaller break-bulk cargoes, automobiles, containers, heavy lifts, dangerous goods, and out-of-gauge cargoes.\nContainer cargo includes a number of risks for the crew, the ship, and the environment. Stowage, cargo securing, stability and\nstress calculations, dangerous goods segregation, mis-declared overweight containers, out of gauge containers, refrigerated\ncontainers, on deck and under deck stowage, half door or both door open containers, lashing strength, sailing conditions,\nvisibility, and heavy weather all pose risks to the ship, crew, and environment if not addressed properly.\nMSC-MEPC.2/Circ.2 of 1 June 2006, “IMO requirements on carriage of publications on board ships” provides the publications\nwhich are specifically required to be carried on board ships by IMO instruments.\nIMO instruments such as the SOLAS, MARPOL, LL, COLREG and STCW Conventions deal with many operational aspects,\ninter alia, navigational responsibilities, safety-related training/drills on board, safe cargo handling, oil spill prevention, collision\navoidance activities and watchkeeping standards.\nTherefore, these publications, although not expressly required by IMO instruments, may need to be carried on board to\nimprove the crew’s knowledge and to enhance the implementation of IMO instruments. No Finding should be filed by the\ninspector against ships not carrying such publications on board unless otherwise required by the ships Safety Management\nSystem manual.\n(IMO REQUIREMENTS ON CARRIAGE OF PUBLICATIONS ON BOARD SHIPS, 2006)\nWhen a vessel is a gravity-based self-unloading and/or hybrid self-unloading type discharging bulk cargo either onshore or\noffshore, the following should be included in the SMS:\n> Starting procedure\n> How to avoid overloading the self-unloading system\n> Stopover procedure –Prevent forging material that may in the cargo hold hopper gates and damage the belt\n> Selecting a variable speed and discharge rate\n> Electric and hydraulic controls\n> Hold discharge gate, conveyors, and elevator\n> Boom conveyor\n> Energy isolation permits and isolation/lock\n> Gate problems including:\n> Gate blockage\n> Gate off-track\n> Loss of gate power\n> Foreign object in way of a gate\n> Actuation of emergency stops\n> Cleaning procedure for the gates","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.2","internal_question_no":"04A.002","question_sort_key":4100200.044,"question_text":"Has a safety officer been appointed and adequately trained, onboard safety meetings held regularly and acknowledged by the vessel’s manager, with feedback provided where necessary, and are safety inspections of the main deck, machinery space, accommodation and forecastle store conducted at regular intervals in accordance with the company’s procedures, and are health, safety, and environmental hazards effectively identified?","guide_to_inspection":"The safety officer is the safety adviser aboard the ship and shall provide valuable assistance to the company and to individual\nemployers in meeting the statutory responsibilities for health and safety. Some training may be provided on board, but the safety\nofficer should have attended a suitable safety officer’s training course.\nThe safety officer should be familiar with the principles and practice of risk assessment and should be available to advise those\npreparing and reviewing risk assessments.\n(Code of Safe Working Practices for Merchant Seafarer’s 2024)\nThe Safety Officer training course shall adhere to the STCW Code 2010 Tables A-II/2 and A-III/2 and the IMO Model Course 3.11 .\nThe safety committee is a forum for consultation between the master, safety officials and others of matters relating to health and\nsafety. It may be used by individual employers for consultation with the company and seafarers. Its effectiveness will depend on the\ncommitment of its members, in particular that of the master.Because of its broad membership, and because the master chairs it,\nthe committee can take effective action in all matters it discusses other than those requiring the authorisation of the company and\nindividual employers. Do not use safety committee meetings for instruction or training.\nThe frequency of meetings will be determined by circumstances, but the committee should meet regularly, considering the pattern\nof operation of the ship and the arrangement for manning, and frequently enough to ensure continuous improvement in safety. In\nparticular, a meeting should also take place after any serious incident or accident on the ship, if the normal meeting is not due within\na week.\nThe vessel manager should establish a procedure requiring regular safety inspections to identify hazards and potential risks to\nhealth, safety, and the environment across all accessible areas of the ship. This includes the main deck areas, forecastle, machinery\nspace, and accommodation block. These inspections should be conducted at appropriate intervals by the designated Safety\nOfficer. A specific checklist should be developed to facilitate these inspections.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":40,"source_page_end":40,"raw_source_text":"Has a safety officer been appointed and adequately trained, onboard safety meetings held regularly and\nacknowledged by the vessel’s manager, with feedback provided where necessary, and are safety inspections\nof the main deck, machinery space, accommodation and forecastle store conducted at regular intervals in\naccordance with the company’s procedures, and are health, safety, and environmental hazards effectively identified? (V)\nGuide to Inspection\nThe safety officer is the safety adviser aboard the ship and shall provide valuable assistance to the company and to individual\nemployers in meeting the statutory responsibilities for health and safety. Some training may be provided on board, but the safety\nofficer should have attended a suitable safety officer’s training course.\nThe safety officer should be familiar with the principles and practice of risk assessment and should be available to advise those\npreparing and reviewing risk assessments.\n(Code of Safe Working Practices for Merchant Seafarer’s 2024)\nThe Safety Officer training course shall adhere to the STCW Code 2010 Tables A-II/2 and A-III/2 and the IMO Model Course 3.11 .\nThe safety committee is a forum for consultation between the master, safety officials and others of matters relating to health and\nsafety. It may be used by individual employers for consultation with the company and seafarers. Its effectiveness will depend on the\ncommitment of its members, in particular that of the master.Because of its broad membership, and because the master chairs it,\nthe committee can take effective action in all matters it discusses other than those requiring the authorisation of the company and\nindividual employers. Do not use safety committee meetings for instruction or training.\nThe frequency of meetings will be determined by circumstances, but the committee should meet regularly, considering the pattern\nof operation of the ship and the arrangement for manning, and frequently enough to ensure continuous improvement in safety. In\nparticular, a meeting should also take place after any serious incident or accident on the ship, if the normal meeting is not due within\na week.\nThe vessel manager should establish a procedure requiring regular safety inspections to identify hazards and potential risks to\nhealth, safety, and the environment across all accessible areas of the ship. This includes the main deck areas, forecastle, machinery\nspace, and accommodation block. These inspections should be conducted at appropriate intervals by the designated Safety\nOfficer. A specific checklist should be developed to facilitate these inspections.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.3","internal_question_no":"04A.003","question_sort_key":4100300.045,"question_text":"Are the latest shipboard internal and external audits, as well as the superintendent inspection reports, available? Are corrective actions being taken in response to recorded non-conformances?","guide_to_inspection":"Internal audits should be held as required by the management system, at intervals not exceeding twelve months. Reports should be\navailable on board. The interval of internal audit may be exceeded by not more than three months in exceptional circumstances. Internal\naudits should be conducted by personnel with a working knowledge of the vessel manager Safety Management System.\nThe vessel’s manager is responsible for establishing an inspection program. This program should ensure that the vessel undergoes\nregular assessments by both Marine and Technical Superintendents. A systematic inspection of the vessel should be carried out, and the\nfrequency of these visits should be clearly defined within the relevant procedures.\nInspections should be scheduled at six-month intervals, with a permissible tolerance of one month. However, the interval between\ninspections should not normally exceed seven months. Additionally, the interval between successive inspections conducted by either a\nMarine Superintendent or a Technical Superintendent should not exceed fourteen months.\nThe term systematic inspection refers to a structured process developed by the vessel’s manager, resulting in an inspection report that\nrecords findings in a standardised format. This report should provide a comprehensive overview of the condition of all operational and\naccessible areas of the vessel, its equipment, and onboard management, thereby informing shore-based management.\nThe inspection report should:\n> Summarise any structural, machinery, or equipment defects identified during the inspection. These should be entered into the\nvessel’s defect reporting system for follow-up and closure.\n> Highlight any procedural weaknesses, which should be addressed through the non-conformity process.\n> B e retained onboard as a complete record of each superintendent’s visit.\nAn internal audit conducted by a Marine and/or Technical Superintendent may be counted as one of the superintendent’s visits, provided a\nseparate inspection report is prepared in addition to the documented audit report.\nRemote Inspections\nWhere a vessel manager has implemented a formal remote vessel inspection program to cover vessels that cannot reasonably be visited\nby a company superintendent, such inspections may be accepted as qualifying visits, provided the following conditions are met:\n> The company has an established procedure for conducting remote vessel inspections, which clearly defines:\n> The circumstances under which a remote inspection may substitute for a physical inspection.\n> The processes used to verify the condition of all areas of the vessel under inspection.\n> The required content and format of the final inspection report.\n> Completed inspection reports, prepared in accordance with the company’s procedure, are available for each remote superintendent\ninspection.\nVisits by senior management, Electrical Superintendents, or Marine and Technical Superintendents that are conducted to address specific\nissues and do not result in a full inspection or a completed report are not considered qualifying inspections under this criterion.\nThe superintendent inspection should be conducted by personnel with working knowledge of the vessel’s Safety Management System,\nand the use of a third-party company is not considered a qualifying inspection under these criteria.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":40,"source_page_end":40,"raw_source_text":"Are the latest shipboard internal and external audits, as well as the superintendent inspection reports,\navailable? Are corrective actions being taken in response to recorded non-conformances?\nGuide to Inspection\nInternal audits should be held as required by the management system, at intervals not exceeding twelve months. Reports should be\navailable on board. The interval of internal audit may be exceeded by not more than three months in exceptional circumstances. Internal\naudits should be conducted by personnel with a working knowledge of the vessel manager Safety Management System.\nThe vessel’s manager is responsible for establishing an inspection program. This program should ensure that the vessel undergoes\nregular assessments by both Marine and Technical Superintendents. A systematic inspection of the vessel should be carried out, and the\nfrequency of these visits should be clearly defined within the relevant procedures.\nInspections should be scheduled at six-month intervals, with a permissible tolerance of one month. However, the interval between\ninspections should not normally exceed seven months. Additionally, the interval between successive inspections conducted by either a\nMarine Superintendent or a Technical Superintendent should not exceed fourteen months.\nThe term systematic inspection refers to a structured process developed by the vessel’s manager, resulting in an inspection report that\nrecords findings in a standardised format. This report should provide a comprehensive overview of the condition of all operational and\naccessible areas of the vessel, its equipment, and onboard management, thereby informing shore-based management.\nThe inspection report should:\n> Summarise any structural, machinery, or equipment defects identified during the inspection. These should be entered into the\nvessel’s defect reporting system for follow-up and closure.\n> Highlight any procedural weaknesses, which should be addressed through the non-conformity process.\n> B e retained onboard as a complete record of each superintendent’s visit.\nAn internal audit conducted by a Marine and/or Technical Superintendent may be counted as one of the superintendent’s visits, provided a\nseparate inspection report is prepared in addition to the documented audit report.\nRemote Inspections\nWhere a vessel manager has implemented a formal remote vessel inspection program to cover vessels that cannot reasonably be visited\nby a company superintendent, such inspections may be accepted as qualifying visits, provided the following conditions are met:\n> The company has an established procedure for conducting remote vessel inspections, which clearly defines:\n> The circumstances under which a remote inspection may substitute for a physical inspection.\n> The processes used to verify the condition of all areas of the vessel under inspection.\n> The required content and format of the final inspection report.\n> Completed inspection reports, prepared in accordance with the company’s procedure, are available for each remote superintendent\ninspection.\nVisits by senior management, Electrical Superintendents, or Marine and Technical Superintendents that are conducted to address specific\nissues and do not result in a full inspection or a completed report are not considered qualifying inspections under this criterion.\nThe superintendent inspection should be conducted by personnel with working knowledge of the vessel’s Safety Management System,\nand the use of a third-party company is not considered a qualifying inspection under these criteria.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.4","internal_question_no":"04A.004","question_sort_key":4100400.046,"question_text":"Does the Master periodically review the effectiveness of the onboard Safety Management System, report the findings to shore based management and receive feedback from them?","guide_to_inspection":"Effective Master reviews should be carried out at least once every 12 months and evidence of the company’s response to\nthe Master’s review should be available on board. The review should contain evidence of positive and negative feedback,\nrather than simply being a tick-box exercise with no substantial content. The review may also include input from the ship’s\nmanagement team.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":41,"source_page_end":41,"raw_source_text":"Does the Master periodically review the effectiveness of the onboard Safety Management System, report\nthe findings to shore based management and receive feedback from them? (M)\nGuide to Inspection\nEffective Master reviews should be carried out at least once every 12 months and evidence of the company’s response to\nthe Master’s review should be available on board. The review should contain evidence of positive and negative feedback,\nrather than simply being a tick-box exercise with no substantial content. The review may also include input from the ship’s\nmanagement team.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.5","internal_question_no":"04A.005","question_sort_key":4100500.047,"question_text":"Is the vessel provided with an enclosed space entry procedure, and is there documented evidence that it was followed, and is there evidence that the crew assigned to responsibilities requiring entry into enclosed spaces has attended a dedicated enclosed space entry course?","guide_to_inspection":"Rightship recommends that if the ballast treatment system is installed in an independent enclosed compartment, such\ncompartment shall be identified as an enclosed space.\nPersons entering enclosed spaces should be provided with calibrated and tested personal gas detection instrument or\ninstruments that monitor the levels of oxygen, carbon dioxide, flammable gases or vapours, toxic gases (including carbon\nmonoxide), and any other gases identified in the risk assessment. (IMO RESOLUTION MSC.581(110) 2025)\nRecord a finding if there is evidence that any person entered the enclosed space without a certified and calibrated personal\ngas detector.\nShips carrying solid bulk cargoes\nOn ships carrying solid bulk cargoes, dangerous atmospheres may develop within cargo spaces, connected and adjacent\nspaces. The hazards may include flammability, toxicity, oxygen depletion, carbon dioxide and/or carbon monoxide generation,\nor self-heating, as identified in the shipper’s declaration and/or in the individual schedules in appendix 1 of the IMSBC Code.\nSolid bulk cargoes listed in the IMSBC Code should be carried in accordance with the provisions of the Code, including\nprecautions, atmosphere testing, ventilation and other requirements specified. Solid bulk cargoes that are not listed in the\nIMSBC Code should be carried in accordance with section 1.3 of the Code, including the conditions for carriage and handling\nas determined by the relevant competent authorities. Grain cargoes and timber cargoes other than those listed in the IMSBC\nCode4 may also cause oxygen depletion and toxic gas emissions, primarily carbon dioxide, in cargo holds and connected and\nadjacent spaces.\nEnclosed hold access trunks\nIn certain designs of hold access, a stair arrangement, sometimes referred to as the “Australian Ladder”, substitutes for a\nvertical ladder. On some ships these are contained within enclosed protective structures that are open only at the top and\nbottom of the hold. When a cargo that presents the risk of a hazardous atmosphere is loaded, this “connected” space will\nquickly adopt atmospheric attributes similar to that of the source space. The enclosed Australian ladder access should not\nbe used until it has been fully ventilated, tested and confirmed to be safe. It should be noted that such spaces are difficult to\nventilate, unless cargo blocking the bottom of the ladder is removed.\nWhen hatches are opened to ventilate the above cargo space at discharge, the hazardous atmosphere often gets trapped in\nthe access trunk.\nWhere such type of access trunk is fitted on ships, the nature of the hazard should be identified outside the entrance to the\nspace and should be listed in the Enclosed Space Register. When a cargo which may generate a hazardous atmosphere is\nloaded, the access door/hatch should be locked with a dedicated and unique locking arrangement, distinct from all other\nsuch arrangements, from the commencement of loading until the space is certified safe for entry by testing after completion\nof discharge.\nEntry of personnel into a cargo hold using a hold vertical ladder should only be permitted when:\n1. the atmosphere in the hold has been tested and found to be safe;\n2. wearing a personal gas detector;\n3. wearing a safety harness; and\n4. an emergency response plan is in place.\nWorking spaces with connections to cargo holds\nIn certain designs of general cargo ships, bulk carriers and tankers, doors and ventilation trunks of cargo spaces, as well as\npipework connecting to cargo spaces, are connected directly into working spaces such as forecastle workspaces, stores\nrooms, windlass hydraulics, bow thruster and other machinery rooms. When a certain cargo is stowed in the cargo space,\nthere is a risk that gas or vapours from the cargo will penetrate into the connected working space.\nThese working spaces should be identified as “connected spaces” and consideration should be given to use of certified safe\ntype of electrical equipment for an explosive atmosphere.\nWhen the cargo space contains a hazardous atmosphere and, given the propensity for hazardous atmospheres to be trapped\nin those spaces, these connected spaces should continue to be considered hazardous until the atmosphere is ensured to be\ngas free by the test.\nAction to be taken in the event of an emergercy\nThe guidance contained in resolution A.1072(28) should be understood and form the basis of any emergency response plan.\nIn the event of an emergency in an enclosed space the ship’s crew should follow the ship-specific enclosed space emergency\nresponse plan. In an emergency the ship’s crew, or any shore personnel, should NEVER perform rescue entering an enclosed\nspace independently, but should always follow the agreed rescue plan.\nThe urge to enter an enclosed space where an accident has occurred is immense and should be always resisted. Many\nenclosed space accidents have been compounded by the good intentions of inadequately equipped ad hoc rescue attempts\nwhere the would-be rescuers have themselves become casualties.\nIf in port, a simple explanation of the enclosed space procedures placed at the entry to the ship together with an agreed\nemergency response plan will greatly assist the efficient rescue of any casualties following an enclosed space accident\noccurring on board the ship.\nA clear understanding of the response required by ship and shore rescue teams will be most advantageous, even essential.\nIt is critical that the ship has an enclosed space emergency response plan, which is easily understood, regularly practised,\nverified as effective and followed precisely.\nThe emergency response plan should form a part of the company SMS.\nEquipment should be provided for the ship’s crew to utilize in the event of an enclosed space accident. Such equipment\nshould fall into three main categories:\n1. Equipment to test and verify the enclosed space atmospheric conditions and determine the hazards to life and the\nmitigations necessary prior to entry;\n2. Equipment to ensure the safety of the rescue party such as self-contained breathing apparatus (SCBA), lifelines, harness,\netc.; and\n3. Equipment to facilitate the safe recovery of a casualty, such as recovery hoist, stretchers and resuscitation equipment.\nThe rescue of a casualty should be undertaken in a steady, controlled and methodical way. The aim is the safe rescue of the\ncasualty without needlessly endangering the lives of\nthose undertaking the rescue operation.\nAn example of an Enclosed Space Emergency Response Plan is contained in appendix of Resolution MSC.581(110)\n(IMO RESOLUTION MSC.581(110) 2025)\nA dangerous space may not necessarily be enclosed on all sides. Some places may not be considered dangerous spaces\nbut the atmosphere may become dangerous because of a change in the condition inside or in the degree of enclosure or\nconfinement, which may occur intermittently, e.g.cargo space access ways.\n(Code of Safe Working Practices for Merchant Seafarer’s 2024)\nThe validity of the entry permit should be specified based on the risk assessment and should never be longer than eight\nhours. The company should ensure that single person entry into an enclosed space is not permitted.\n(IMO RESOLUTION MSC.581(110) 2025)\nIt should also state in the entry permit the maximum permitted time between atmosphere-testing of spaces and when\nthey are entered by personnel, as well as maximum time permitted between testing while the space is occupied. It is\nrecommended this period should not exceed 30 minutes between testing and that records of the tests are maintained, and\nthis should be defined in the operator’s SMS.\n(International safety guide for oil tankers & terminals, 2020).\nConnected space means a space that is connected, by either permanent or temporary means (such as a door), to a source\nspace that may contain a hazardous atmosphere.\nFor clarity, a space separated by a manual door, even if watertight, should be considered as “connected” as it is impossible\nto tell from outside the space whether it is open or closed or indeed properly sealed. A connected space should be treated\nas containing a hazardous atmosphere until testing proves otherwise. The nature of the connection may lead to a “trapped\nhazardous atmosphere”.\nAdjacent space means a space that shares a common boundary with a compartment that may contain a hazardous\natmosphere. Such a space has no openings, temporary or permanent, into the hazardous compartment whatsoever and is\ndesigned to be a contiguous barrier. Such a space may only contain a hazardous atmosphere in the event of failure of that\nbarrier. Precautions should relate to the possibility of such a failure.\nTrapped Hazardous Atmosphere means a hazardous atmosphere that may be trapped in a connected space in a manner\nthat causes that space’s atmosphere to fill and/or to empty at a different rate to the source space. Such a space, while\nrecognized as containing the same atmosphere, should be treated independently to the source space, and should be\nassumed to contain a hazardous atmosphere until proved otherwise by testing. For example, a trapped atmosphere may\nremain even after the cargo in the source space is discharged.\nCompetent person means a person with an operational level of competency to make an informed assessment of the\nlikelihood of a dangerous atmosphere being present or subsequently arising in the space.\nResponsible person means a person in a management level on board a ship (i.e. master, chief mate, chief engineer officer or\nsecond engineer officer) of competency and authorized by the shipping company to permit entry into an enclosed space.\nAttendant means a person maintains a watch over those entering the enclosed space, to maintain communications with\nthose inside the space and to initiate the emergency procedures in the event of an incident occurring.\n(IMO RESOLUTION MSC.581(110) 2025)\nEnclosed Space Register means a ship-specific register which lists all enclosed spaces on board the ship, along with their\nconnected spaces and adjacent spaces, their hazards, associated risk mitigations if applicable, and how the atmosphere in\nthese spaces may change depending upon the nature of cargo carried or the content of the space, and which forms a part of\nthe safety management for enclosed spaces.\nIdentification of the hazards and assessment of risk\nThe company should ensure that a risk assessment is conducted to identify all enclosed spaces on board the ship and that\nthe identified enclosed spaces are recorded in the Enclosed Space Register, which should be maintained on board the ship\nas well as ashore. This Enclosed Space Register and risk assessment should be kept up to date as appropriate to ensure its\ncontinued validity, particularly after loading and during the carriage of cargoes which may adversely affect the safety of the\natmosphere within a space. A reassessment should also be made when the contents of the space change, such as in case a\nship stores treated sewage or grey water temporarily in its ballast water tanks.\nThe company should consider the use of appropriate technology to assist in the hazard identification and mitigation. The\nEnclosed Space Register and risk assessment should form the basis of the development of the enclosed space emergency\nresponse plan (appendix 1 of IMO RESOLUTION MSC.581(110)).\nIt is recommended that the enclosed space emergency response plan be reviewed after each drill so that its effectiveness\ncan be assessed and, if necessary, improvements made. As entries for enclosed spaces other than cargo spaces may be\ndifferent, there is a need to record information for the benefit of personnel involved.\nEvery ship should have an Enclosed Space Register, the information within which may form the basis of a risk assessment.\nThe Enclosed Space Register should contain:\n1. physical layout of the space and access and egress points, including of connected spaces, if any;\n2. physical hazards in the space, e.g. vertical ladders, unguarded openings, poor lighting, wet or slippery conditions, excessive\nheat;\n3. connection to adjacent spaces;\n4. specific hazards within the space, for example, the effect of ballast water treatment method on the atmosphere within\nballast tanks;\n5. if used, information related to additional technology, helping to determine enclosed space condition;\n6. information related to fixed and portable ventilation systems including equipment and where the equipment is stored;\n7. estimated time taken to achieve the air changes for safe entry, using forced or natural ventilation;\n8. lighting and means for temporary lighting including intrinsically safe lighting where appropriate;\n9. means for atmosphere testing;\n10. any pertinent information that would assist the risk assessment process;\n11. locking and “Safe to enter”/”Unsafe to enter” signage arrangements; and\n12. the equipment necessary to facilitate emergency rescue from the space.\nTraining and awareness\nOnly trained and authorized personnel should be assigned the duties of entering, functioning as attendants or acting as members\nof rescue teams. Ships’ crews with rescue and first aid duties should be drilled periodically as required by SOLAS regulation\nIII/19.3.6 in rescue and first aid procedures.\nTraining should include as a minimum:\n1. identification of the hazards likely to be faced during entry into enclosed spaces and whilst within the space, in particular the\nrapidity with which oxygen may be depleted in a space by corrosion or biological means especially in higher ambient temperatures.\nThe pace at which oxygen gets depleted increases exponentially when ventilation is stopped (fan or other equipment in case of\nforced ventilation, and closing a vent or damper in case of natural ventilation) or other characteristics or properties of the contents\nor structure of the space. While higher ambient temperatures can increase the rate of oxygen depletion, it should be assumed that\nthe rate of depletion will always be very rapid, regardless of the ambient temperature;\n2. an explanation of how the pace at which oxygen is depleted will increase exponentially when ventilation is stopped (fan or other\nequipment in case of forced ventilation, and closing a vent or damper in case of natural ventilation), or when hatch covers are\nclosed;\n3. identification and use of the various sources of information on the hazards associated with individual solid bulk and liquid bulk\ncargoes, and the precautions to be adopted when entering spaces containing such cargoes, or their residues;\n4. awareness of the fact that when a person or persons in an enclosed space shows signs of adverse health effects, that they\nshould always assume that these effects are due to an oxygen-depleted or toxic atmosphere in the space, and that they should not\nenter it themselves;\n5. recognition of the signs of adverse health effects caused by exposure to hazards during entry;\n6. knowledge and experience in the use of personal protective equipment required for entry;\n7. rescue, first aid, Cardio Pulmonary Resuscitation (CPR) techniques and evacuation procedures;\n8. knowledge and experience in the use of communication equipment and procedures;\n9. knowledge and experience in the use of instruments for measuring the atmosphere;\n10. knowledge and experience in the use of rescue equipment and procedures;\n11. knowledge of the IMO/WHO/ILO Medical First Aid Guide for Use in Accidents involving Dangerous Goods (MFAG), where\nappropriate; and\n12. knowledge of use of emergency and the first aid equipment for chemical tankers (IBC Code section 14.3) and for gas carriers\n(IGC Code section 14.3), where appropriate.\n(IMO RESOLUTION MSC.581(110) 2025)\nDrills:\nDrills must be participated in by seafarers whose responsibilities include entry into or rescue from enclosed spaces.\nEntrances to Enclosed Spaces\nEntry doors or access hatches leading to enclosed spaces should at all times be secured against entry unless the spaces have\nbeen risk assessed, atmospherically tested as required and declared safe for entry. The ship may use a system of seals similar to\nthose recommended in the ISPS Code. Suitable portable signage, which is easily understandable by the vessel’s crew and also by\nshore personnel engaged on the ship at this time and in the port,\nindicating the hazards should be posted on entry doors or access hatches leading to an enclosed space. An example of such\nsignage is contained within appendix 3. These signs should be updated when the space becomes safe for entry or when a safe\nspace becomes unsafe.\nA door or hatch cover which is opened to provide natural ventilation of an enclosed space may, wrongly, be taken to be an indication\nof a safe atmosphere and therefore it is recommended to station an attendant at the entrance or use a mechanical or physical\nbarrier, such as a locked bar or chain positioned across the opening with an attached warning sign, to prevent accidental entry. It is\nrecommended that operations such as these are included in the watch handover activity.\nSafety of Shore Personnel\nBefore any personnel are authorized to enter any cargo space containing any cargo, the competent person should carry out a risk\nassessment of the cargo; identification of the physical characteristics of the cargo space(s) concerned; and the operations to be\ncarried out, and the responsible person should:\n1. where it is necessary for shore personnel to enter any such spaces, conduct a pre-operational risk assessment prior to\ncommencement of cargo operations or arrival of shore personnel. When hazards are identified a joint risk assessment with\nterminal representatives responsible for operations on board the ship, or with other appropriate shore personnel, should be\nconducted; and\n2. identify and agree to the precautions required during entry and enclosed space entry permit arrangements to be used.\n(IMO RESOLUTION MSC.581(110) 2025)\nRisk Assessment of an Enclosed Space\nIn order to ensure safety from the outset, entry and occupancy, a competent person should make an assessment of any potential\nhazards in the space to be entered, taking into account the characteristics of the previous and current cargo carried with Safety\nData Sheets (SDS) and cargo information, ventilation of the space, coating of the space and other relevant factors. Opening of an\nenclosed space should be subject to a risk assessment, taking into consideration the potential for release of dangerous gases or\npotential to create an explosive atmosphere: the competent person’s assessment should determine the potential for the presence\nof an oxygen-deficient, oxygen-enriched, flammable or toxic atmosphere, which includes carbon monoxide (CO) and carbon\ndioxide (CO2) as well as other toxic or asphyxiant gases.\nThe competent person should bear in mind that the ventilation procedures for an adjacent or connected space may be different\nfrom those for the enclosed space itself. The details of the assessment should be recorded in a standard format, and maintained on\nboard the ship.\nThe nature of the hazards that may be present should be fully understood by those on board the ship, both crew and shore-based\npersonnel, and those ashore managing the ship.\nThe procedures to be followed for testing the atmosphere in the space and for entry should be decided on the basis of the\nassessment. These will depend on whether the assessment shows that:\n1. there is minimal risk to the health or life of personnel entering the space; or\n2. there is no immediate risk to health or life, but a risk could arise during the course of work in the space; or\n3. a risk to health or life is identified.\nWhere the assessment indicates minimal risk to health or life or potential for a risk to arise during the course of work in the space,\nthe precautions described in sections 5 to 8\nand 10 of MSC581 ( 110) should be followed, as appropriate.\nWhere the assessment identifies a risk to life or health, if entry is to be made, the additional precautions specified in section 9 of\nMSC581 ( 110)) should also be followed.\nThroughout the assessment process, there should be an assumption that the space to be entered is considered as hazardous until\npositively proved to be safe for entry.\nAfter completion of a suitable risk assessment targeted to the space to be entered steady readings of all of the following should be\nobtained:\n1. 20.9% oxygen by volume;\n2. the level of carbon dioxide has been checked and is less than 0.5% by volume (5,000 ppm);\nNote: National requirements may differ when determining the safe atmosphere range for gases stated above.\n3. less than 1% of lower flammable limit (LFL) on a suitably sensitive combustible gas indicator, where the assessment has\ndetermined that there is potential for flammable gases or vapours; and\n4. less than 50% of the occupational exposure limit (OEL) of any toxic vapours and gases.\n(IMO RESOLUTION MSC.581(110) 2025)\nPersonal Protective Equipment (PPE)\nWhen considering the planned work activity within an enclosed space where the atmosphere is known or suspected to be unsafe,\nsuitably designed and constructed breathing apparatus of positive pressure type should always be worn, and only personnel\ntrained in its use should be allowed to enter the space. Air-purifying respirators, dust masks and canister face masks do not provide\na supply of clean air from a source independent of the atmosphere within the space and should not be used.\nEmergency Escape Breathing Devices (EEBDs) are not suitable to use for entry into enclosed spaces.\nNotwithstanding paragraph 6.5.6 of MSC581(110) , persons entering enclosed spaces that may contain a suspected atmospheric\nhazard should be provided with calibrated and tested personal gas detector suitable for the gas or gases assessed as likely to\noccur in the space.\nRescue harnesses should be worn and unless impractical, lifelines should also be used. A means to facilitate evacuation from the\nenclosed space should be available and ready for use, as per emergency response plan.\nAppropriate protective clothing should be worn, particularly where there is any risk of toxic substances or chemicals coming into\ncontact with the skin of those entering the space.\n(IMO RESOLUTION MSC.581(110) 2025)\nRightShip recommends that the enclosed space entry procedure comprise at a minimum the following:\n> Define enclosed space.\n> Dangers associated with enclosed space atmospheres\n> Identify a enclosed space\n> Precautions in general\n> Entry authorization\n> Requirements for entrance into enclosed space\n> Precautions to take before entering an enclosed space\n> Work in enclosed space\n> Education and awareness\n> An enclosed space’s risk assessment\n> Drills\n> Requirement for personal protective equipment\n> Requirements for equipment and testing\n> Evacuation and rescue from enclosed spaces\n> Entering enclosed spaces with known or suspected hazardous atmospheres","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":41,"source_page_end":45,"raw_source_text":"Is the vessel provided with an enclosed space entry procedure, and is there documented evidence that it was\nfollowed, and is there evidence that the crew assigned to responsibilities requiring entry into enclosed spaces\nhas attended a dedicated enclosed space entry course?\nGuide to Inspection\nRightship recommends that if the ballast treatment system is installed in an independent enclosed compartment, such\ncompartment shall be identified as an enclosed space.\nPersons entering enclosed spaces should be provided with calibrated and tested personal gas detection instrument or\ninstruments that monitor the levels of oxygen, carbon dioxide, flammable gases or vapours, toxic gases (including carbon\nmonoxide), and any other gases identified in the risk assessment. (IMO RESOLUTION MSC.581(110) 2025)\nRecord a finding if there is evidence that any person entered the enclosed space without a certified and calibrated personal\ngas detector.\nShips carrying solid bulk cargoes\nOn ships carrying solid bulk cargoes, dangerous atmospheres may develop within cargo spaces, connected and adjacent\nspaces. The hazards may include flammability, toxicity, oxygen depletion, carbon dioxide and/or carbon monoxide generation,\nor self-heating, as identified in the shipper’s declaration and/or in the individual schedules in appendix 1 of the IMSBC Code.\nSolid bulk cargoes listed in the IMSBC Code should be carried in accordance with the provisions of the Code, including\nprecautions, atmosphere testing, ventilation and other requirements specified. Solid bulk cargoes that are not listed in the\nIMSBC Code should be carried in accordance with section 1.3 of the Code, including the conditions for carriage and handling\nas determined by the relevant competent authorities. Grain cargoes and timber cargoes other than those listed in the IMSBC\nCode4 may also cause oxygen depletion and toxic gas emissions, primarily carbon dioxide, in cargo holds and connected and\nadjacent spaces.\nEnclosed hold access trunks\nIn certain designs of hold access, a stair arrangement, sometimes referred to as the “Australian Ladder”, substitutes for a\nvertical ladder. On some ships these are contained within enclosed protective structures that are open only at the top and\nbottom of the hold. When a cargo that presents the risk of a hazardous atmosphere is loaded, this “connected” space will\nquickly adopt atmospheric attributes similar to that of the source space. The enclosed Australian ladder access should not\nbe used until it has been fully ventilated, tested and confirmed to be safe. It should be noted that such spaces are difficult to\nventilate, unless cargo blocking the bottom of the ladder is removed.\nWhen hatches are opened to ventilate the above cargo space at discharge, the hazardous atmosphere often gets trapped in\nthe access trunk.\nWhere such type of access trunk is fitted on ships, the nature of the hazard should be identified outside the entrance to the\nspace and should be listed in the Enclosed Space Register. When a cargo which may generate a hazardous atmosphere is\nloaded, the access door/hatch should be locked with a dedicated and unique locking arrangement, distinct from all other\nsuch arrangements, from the commencement of loading until the space is certified safe for entry by testing after completion\nof discharge.\nEntry of personnel into a cargo hold using a hold vertical ladder should only be permitted when:\n1. the atmosphere in the hold has been tested and found to be safe;\n2. wearing a personal gas detector;\n3. wearing a safety harness; and\n4. an emergency response plan is in place.\nWorking spaces with connections to cargo holds\nIn certain designs of general cargo ships, bulk carriers and tankers, doors and ventilation trunks of cargo spaces, as well as\npipework connecting to cargo spaces, are connected directly into working spaces such as forecastle workspaces, stores\nrooms, windlass hydraulics, bow thruster and other machinery rooms. When a certain cargo is stowed in the cargo space,\nthere is a risk that gas or vapours from the cargo will penetrate into the connected working space.\nThese working spaces should be identified as “connected spaces” and consideration should be given to use of certified safe\ntype of electrical equipment for an explosive atmosphere.\nWhen the cargo space contains a hazardous atmosphere and, given the propensity for hazardous atmospheres to be trapped\nin those spaces, these connected spaces should continue to be considered hazardous until the atmosphere is ensured to be\ngas free by the test.\nAction to be taken in the event of an emergercy\nThe guidance contained in resolution A.1072(28) should be understood and form the basis of any emergency response plan.\nIn the event of an emergency in an enclosed space the ship’s crew should follow the ship-specific enclosed space emergency\nresponse plan. In an emergency the ship’s crew, or any shore personnel, should NEVER perform rescue entering an enclosed\nspace independently, but should always follow the agreed rescue plan.\nThe urge to enter an enclosed space where an accident has occurred is immense and should be always resisted. Many\nenclosed space accidents have been compounded by the good intentions of inadequately equipped ad hoc rescue attempts\nwhere the would-be rescuers have themselves become casualties.\nIf in port, a simple explanation of the enclosed space procedures placed at the entry to the ship together with an agreed\nemergency response plan will greatly assist the efficient rescue of any casualties following an enclosed space accident\noccurring on board the ship.\nA clear understanding of the response required by ship and shore rescue teams will be most advantageous, even essential.\nIt is critical that the ship has an enclosed space emergency response plan, which is easily understood, regularly practised,\nverified as effective and followed precisely.\nThe emergency response plan should form a part of the company SMS.\nEquipment should be provided for the ship’s crew to utilize in the event of an enclosed space accident. Such equipment\nshould fall into three main categories:\n1. Equipment to test and verify the enclosed space atmospheric conditions and determine the hazards to life and the\nmitigations necessary prior to entry;\n2. Equipment to ensure the safety of the rescue party such as self-contained breathing apparatus (SCBA), lifelines, harness,\netc.; and\n3. Equipment to facilitate the safe recovery of a casualty, such as recovery hoist, stretchers and resuscitation equipment.\nThe rescue of a casualty should be undertaken in a steady, controlled and methodical way. The aim is the safe rescue of the\ncasualty without needlessly endangering the lives of\nthose undertaking the rescue operation.\nAn example of an Enclosed Space Emergency Response Plan is contained in appendix of Resolution MSC.581(110)\n(IMO RESOLUTION MSC.581(110) 2025)\nA dangerous space may not necessarily be enclosed on all sides. Some places may not be considered dangerous spaces\nbut the atmosphere may become dangerous because of a change in the condition inside or in the degree of enclosure or\nconfinement, which may occur intermittently, e.g.cargo space access ways.\n(Code of Safe Working Practices for Merchant Seafarer’s 2024)\nThe validity of the entry permit should be specified based on the risk assessment and should never be longer than eight\nhours. The company should ensure that single person entry into an enclosed space is not permitted.\n(IMO RESOLUTION MSC.581(110) 2025)\nIt should also state in the entry permit the maximum permitted time between atmosphere-testing of spaces and when\nthey are entered by personnel, as well as maximum time permitted between testing while the space is occupied. It is\nrecommended this period should not exceed 30 minutes between testing and that records of the tests are maintained, and\nthis should be defined in the operator’s SMS.\n(International safety guide for oil tankers & terminals, 2020).\nConnected space means a space that is connected, by either permanent or temporary means (such as a door), to a source\nspace that may contain a hazardous atmosphere.\nFor clarity, a space separated by a manual door, even if watertight, should be considered as “connected” as it is impossible\nto tell from outside the space whether it is open or closed or indeed properly sealed. A connected space should be treated\nas containing a hazardous atmosphere until testing proves otherwise. The nature of the connection may lead to a “trapped\nhazardous atmosphere”.\nAdjacent space means a space that shares a common boundary with a compartment that may contain a hazardous\natmosphere. Such a space has no openings, temporary or permanent, into the hazardous compartment whatsoever and is\ndesigned to be a contiguous barrier. Such a space may only contain a hazardous atmosphere in the event of failure of that\nbarrier. Precautions should relate to the possibility of such a failure.\nTrapped Hazardous Atmosphere means a hazardous atmosphere that may be trapped in a connected space in a manner\nthat causes that space’s atmosphere to fill and/or to empty at a different rate to the source space. Such a space, while\nrecognized as containing the same atmosphere, should be treated independently to the source space, and should be\nassumed to contain a hazardous atmosphere until proved otherwise by testing. For example, a trapped atmosphere may\nremain even after the cargo in the source space is discharged.\nCompetent person means a person with an operational level of competency to make an informed assessment of the\nlikelihood of a dangerous atmosphere being present or subsequently arising in the space.\nResponsible person means a person in a management level on board a ship (i.e. master, chief mate, chief engineer officer or\nsecond engineer officer) of competency and authorized by the shipping company to permit entry into an enclosed space.\nAttendant means a person maintains a watch over those entering the enclosed space, to maintain communications with\nthose inside the space and to initiate the emergency procedures in the event of an incident occurring.\n(IMO RESOLUTION MSC.581(110) 2025)\nEnclosed Space Register means a ship-specific register which lists all enclosed spaces on board the ship, along with their\nconnected spaces and adjacent spaces, their hazards, associated risk mitigations if applicable, and how the atmosphere in\nthese spaces may change depending upon the nature of cargo carried or the content of the space, and which forms a part of\nthe safety management for enclosed spaces.\nIdentification of the hazards and assessment of risk\nThe company should ensure that a risk assessment is conducted to identify all enclosed spaces on board the ship and that\nthe identified enclosed spaces are recorded in the Enclosed Space Register, which should be maintained on board the ship\nas well as ashore. This Enclosed Space Register and risk assessment should be kept up to date as appropriate to ensure its\ncontinued validity, particularly after loading and during the carriage of cargoes which may adversely affect the safety of the\natmosphere within a space. A reassessment should also be made when the contents of the space change, such as in case a\nship stores treated sewage or grey water temporarily in its ballast water tanks.\nThe company should consider the use of appropriate technology to assist in the hazard identification and mitigation. The\nEnclosed Space Register and risk assessment should form the basis of the development of the enclosed space emergency\nresponse plan (appendix 1 of IMO RESOLUTION MSC.581(110)).\nIt is recommended that the enclosed space emergency response plan be reviewed after each drill so that its effectiveness\ncan be assessed and, if necessary, improvements made. As entries for enclosed spaces other than cargo spaces may be\ndifferent, there is a need to record information for the benefit of personnel involved.\nEvery ship should have an Enclosed Space Register, the information within which may form the basis of a risk assessment.\nThe Enclosed Space Register should contain:\n1. physical layout of the space and access and egress points, including of connected spaces, if any;\n2. physical hazards in the space, e.g. vertical ladders, unguarded openings, poor lighting, wet or slippery conditions, excessive\nheat;\n3. connection to adjacent spaces;\n4. specific hazards within the space, for example, the effect of ballast water treatment method on the atmosphere within\nballast tanks;\n5. if used, information related to additional technology, helping to determine enclosed space condition;\n6. information related to fixed and portable ventilation systems including equipment and where the equipment is stored;\n7. estimated time taken to achieve the air changes for safe entry, using forced or natural ventilation;\n8. lighting and means for temporary lighting including intrinsically safe lighting where appropriate;\n9. means for atmosphere testing;\n10. any pertinent information that would assist the risk assessment process;\n11. locking and “Safe to enter”/”Unsafe to enter” signage arrangements; and\n12. the equipment necessary to facilitate emergency rescue from the space.\nTraining and awareness\nOnly trained and authorized personnel should be assigned the duties of entering, functioning as attendants or acting as members\nof rescue teams. Ships’ crews with rescue and first aid duties should be drilled periodically as required by SOLAS regulation\nIII/19.3.6 in rescue and first aid procedures.\nTraining should include as a minimum:\n1. identification of the hazards likely to be faced during entry into enclosed spaces and whilst within the space, in particular the\nrapidity with which oxygen may be depleted in a space by corrosion or biological means especially in higher ambient temperatures.\nThe pace at which oxygen gets depleted increases exponentially when ventilation is stopped (fan or other equipment in case of\nforced ventilation, and closing a vent or damper in case of natural ventilation) or other characteristics or properties of the contents\nor structure of the space. While higher ambient temperatures can increase the rate of oxygen depletion, it should be assumed that\nthe rate of depletion will always be very rapid, regardless of the ambient temperature;\n2. an explanation of how the pace at which oxygen is depleted will increase exponentially when ventilation is stopped (fan or other\nequipment in case of forced ventilation, and closing a vent or damper in case of natural ventilation), or when hatch covers are\nclosed;\n3. identification and use of the various sources of information on the hazards associated with individual solid bulk and liquid bulk\ncargoes, and the precautions to be adopted when entering spaces containing such cargoes, or their residues;\n4. awareness of the fact that when a person or persons in an enclosed space shows signs of adverse health effects, that they\nshould always assume that these effects are due to an oxygen-depleted or toxic atmosphere in the space, and that they should not\nenter it themselves;\n5. recognition of the signs of adverse health effects caused by exposure to hazards during entry;\n6. knowledge and experience in the use of personal protective equipment required for entry;\n7. rescue, first aid, Cardio Pulmonary Resuscitation (CPR) techniques and evacuation procedures;\n8. knowledge and experience in the use of communication equipment and procedures;\n9. knowledge and experience in the use of instruments for measuring the atmosphere;\n10. knowledge and experience in the use of rescue equipment and procedures;\n11. knowledge of the IMO/WHO/ILO Medical First Aid Guide for Use in Accidents involving Dangerous Goods (MFAG), where\nappropriate; and\n12. knowledge of use of emergency and the first aid equipment for chemical tankers (IBC Code section 14.3) and for gas carriers\n(IGC Code section 14.3), where appropriate.\n(IMO RESOLUTION MSC.581(110) 2025)\nDrills:\nDrills must be participated in by seafarers whose responsibilities include entry into or rescue from enclosed spaces.\nEntrances to Enclosed Spaces\nEntry doors or access hatches leading to enclosed spaces should at all times be secured against entry unless the spaces have\nbeen risk assessed, atmospherically tested as required and declared safe for entry. The ship may use a system of seals similar to\nthose recommended in the ISPS Code. Suitable portable signage, which is easily understandable by the vessel’s crew and also by\nshore personnel engaged on the ship at this time and in the port,\nindicating the hazards should be posted on entry doors or access hatches leading to an enclosed space. An example of such\nsignage is contained within appendix 3. These signs should be updated when the space becomes safe for entry or when a safe\nspace becomes unsafe.\nA door or hatch cover which is opened to provide natural ventilation of an enclosed space may, wrongly, be taken to be an indication\nof a safe atmosphere and therefore it is recommended to station an attendant at the entrance or use a mechanical or physical\nbarrier, such as a locked bar or chain positioned across the opening with an attached warning sign, to prevent accidental entry. It is\nrecommended that operations such as these are included in the watch handover activity.\nSafety of Shore Personnel\nBefore any personnel are authorized to enter any cargo space containing any cargo, the competent person should carry out a risk\nassessment of the cargo; identification of the physical characteristics of the cargo space(s) concerned; and the operations to be\ncarried out, and the responsible person should:\n1. where it is necessary for shore personnel to enter any such spaces, conduct a pre-operational risk assessment prior to\ncommencement of cargo operations or arrival of shore personnel. When hazards are identified a joint risk assessment with\nterminal representatives responsible for operations on board the ship, or with other appropriate shore personnel, should be\nconducted; and\n2. identify and agree to the precautions required during entry and enclosed space entry permit arrangements to be used.\n(IMO RESOLUTION MSC.581(110) 2025)\nRisk Assessment of an Enclosed Space\nIn order to ensure safety from the outset, entry and occupancy, a competent person should make an assessment of any potential\nhazards in the space to be entered, taking into account the characteristics of the previous and current cargo carried with Safety\nData Sheets (SDS) and cargo information, ventilation of the space, coating of the space and other relevant factors. Opening of an\nenclosed space should be subject to a risk assessment, taking into consideration the potential for release of dangerous gases or\npotential to create an explosive atmosphere: the competent person’s assessment should determine the potential for the presence\nof an oxygen-deficient, oxygen-enriched, flammable or toxic atmosphere, which includes carbon monoxide (CO) and carbon\ndioxide (CO2) as well as other toxic or asphyxiant gases.\nThe competent person should bear in mind that the ventilation procedures for an adjacent or connected space may be different\nfrom those for the enclosed space itself. The details of the assessment should be recorded in a standard format, and maintained on\nboard the ship.\nThe nature of the hazards that may be present should be fully understood by those on board the ship, both crew and shore-based\npersonnel, and those ashore managing the ship.\nThe procedures to be followed for testing the atmosphere in the space and for entry should be decided on the basis of the\nassessment. These will depend on whether the assessment shows that:\n1. there is minimal risk to the health or life of personnel entering the space; or\n2. there is no immediate risk to health or life, but a risk could arise during the course of work in the space; or\n3. a risk to health or life is identified.\nWhere the assessment indicates minimal risk to health or life or potential for a risk to arise during the course of work in the space,\nthe precautions described in sections 5 to 8\nand 10 of MSC581 ( 110) should be followed, as appropriate.\nWhere the assessment identifies a risk to life or health, if entry is to be made, the additional precautions specified in section 9 of\nMSC581 ( 110)) should also be followed.\nThroughout the assessment process, there should be an assumption that the space to be entered is considered as hazardous until\npositively proved to be safe for entry.\nAfter completion of a suitable risk assessment targeted to the space to be entered steady readings of all of the following should be\nobtained:\n1. 20.9% oxygen by volume;\n2. the level of carbon dioxide has been checked and is less than 0.5% by volume (5,000 ppm);\nNote: National requirements may differ when determining the safe atmosphere range for gases stated above.\n3. less than 1% of lower flammable limit (LFL) on a suitably sensitive combustible gas indicator, where the assessment has\ndetermined that there is potential for flammable gases or vapours; and\n4. less than 50% of the occupational exposure limit (OEL) of any toxic vapours and gases.\n(IMO RESOLUTION MSC.581(110) 2025)\nPersonal Protective Equipment (PPE)\nWhen considering the planned work activity within an enclosed space where the atmosphere is known or suspected to be unsafe,\nsuitably designed and constructed breathing apparatus of positive pressure type should always be worn, and only personnel\ntrained in its use should be allowed to enter the space. Air-purifying respirators, dust masks and canister face masks do not provide\na supply of clean air from a source independent of the atmosphere within the space and should not be used.\nEmergency Escape Breathing Devices (EEBDs) are not suitable to use for entry into enclosed spaces.\nNotwithstanding paragraph 6.5.6 of MSC581(110) , persons entering enclosed spaces that may contain a suspected atmospheric\nhazard should be provided with calibrated and tested personal gas detector suitable for the gas or gases assessed as likely to\noccur in the space.\nRescue harnesses should be worn and unless impractical, lifelines should also be used. A means to facilitate evacuation from the\nenclosed space should be available and ready for use, as per emergency response plan.\nAppropriate protective clothing should be worn, particularly where there is any risk of toxic substances or chemicals coming into\ncontact with the skin of those entering the space.\n(IMO RESOLUTION MSC.581(110) 2025)\nRightShip recommends that the enclosed space entry procedure comprise at a minimum the following:\n> Define enclosed space.\n> Dangers associated with enclosed space atmospheres\n> Identify a enclosed space\n> Precautions in general\n> Entry authorization\n> Requirements for entrance into enclosed space\n> Precautions to take before entering an enclosed space\n> Work in enclosed space\n> Education and awareness\n> An enclosed space’s risk assessment\n> Drills\n> Requirement for personal protective equipment\n> Requirements for equipment and testing\n> Evacuation and rescue from enclosed spaces\n> Entering enclosed spaces with known or suspected hazardous atmospheres","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.6","internal_question_no":"04A.006","question_sort_key":4100600.048,"question_text":"Is entry into and rescue from enclosed space training undertaken and are regular drills conducted?","guide_to_inspection":"The company should ensure that rescue drills from enclosed space identified in their Enclosed Space Register are undertaken\nregularly as required by SOLAS regulation III/19.3.6 using the equipment provided to facilitate a rescue from an enclosed\nspace. Such drills should focus on different aspects of operations involving enclosed spaces. SOLAS regulation III/19.3.6\nrequires:\n1. checking and use of personal protective equipment required for entry;\n2. checking and use of communication equipment and procedures;\n3. checking and use of instruments for measuring the atmosphere in enclosed spaces;\n4. checking and use of rescue equipment and procedures; and\n5. instructions in first aid and resuscitation techniques.\n(IMO RESOLUTION MSC.581(110) 2025)\nCrew members with enclosed space entry or rescue responsibilities shall participate in an enclosed space entry and rescue\ndrill to be held on board the ship at least once every two months.\nThe enclosed space entry/rescue drill should include a scenario involving the rescue of a person from the cargo hold,\nincluding access to and retrieval from the space.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":45,"source_page_end":45,"raw_source_text":"Is entry into and rescue from enclosed space training undertaken and are regular drills conducted? (V)\nGuide to Inspection\nThe company should ensure that rescue drills from enclosed space identified in their Enclosed Space Register are undertaken\nregularly as required by SOLAS regulation III/19.3.6 using the equipment provided to facilitate a rescue from an enclosed\nspace. Such drills should focus on different aspects of operations involving enclosed spaces. SOLAS regulation III/19.3.6\nrequires:\n1. checking and use of personal protective equipment required for entry;\n2. checking and use of communication equipment and procedures;\n3. checking and use of instruments for measuring the atmosphere in enclosed spaces;\n4. checking and use of rescue equipment and procedures; and\n5. instructions in first aid and resuscitation techniques.\n(IMO RESOLUTION MSC.581(110) 2025)\nCrew members with enclosed space entry or rescue responsibilities shall participate in an enclosed space entry and rescue\ndrill to be held on board the ship at least once every two months.\nThe enclosed space entry/rescue drill should include a scenario involving the rescue of a person from the cargo hold,\nincluding access to and retrieval from the space.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.7","internal_question_no":"04A.007","question_sort_key":4100700.049,"question_text":"Are procedures in place for the control of hot work, are they incorporated in the safety management system and is there documented evidence of compliance?","guide_to_inspection":"Permits for hot work should be specific regarding the exact risks associated with the specific hot work, location, timing, and\nhazards.\nPermits to hot work should address dangers to all adjacent cargo or other flammable materials that may be exposed, as well\nas the necessity for additional protective covers.\nHot work means any work requiring the use of electric arc or gas welding equipment, cutting burner equipment or other forms\nof naked flame, as well as heating or spark generating tools, regardless of where it is carried out on board a ship. The safety\nmanagement system (SMS) on board should include adequate guidance on control of hot work and should be robust enough\nto ensure compliance. Absence of guidance should be regarded as prohibition, rather than approval.\nWhenever possible, a space such as a workshop where conditions are deemed safe, should be designated for hot work to be\nperformed and first consideration given to performing any hot work in that space.\n> Hot work performed outside that space should be subject to the following considerations.\nHot work outside the designated space:\n> The Master or designated safety officer should be responsible for deciding whether hot work is justified and whether it\ncan be conducted safely.\n> A permit-to-work system should be employed.\n> Hot work procedures should take account of national laws or regulations or other national safety and health rules.\n> A responsible officer, not involved in the hot work, should be designated to ensure that safe procedures are followed.\n> A written plan for the operation should be agreed by all who will have responsibilities in connection with the hot work.\n> The work area should be carefully prepared and isolated before hot work commences.\n> Fire safety precautions should be reviewed, including fire equipment preparations, setting a fire watch in adjacent\ncompartments and areas, and fire-extinguishing measures.\n> Isolation of the work area and fire precautions should be continued until the risk of fire no longer exists.\n(Principles for Hot Work on Board all Types of Ships, 2003)\nHot work in places other than the workshop should be the subject of a permit to work.\n(Code of Safe Working Practices for Merchant Seafarer’s, 2024 )\nHot Work Outside Designated Spaces\nWhen hot work is required outside designated spaces, it is essential to follow strict safety protocols to ensure the operation is\nconducted safely and in compliance with company procedures.\nA written plan for the hot work should be prepared and reviewed prior to commencement by a representative of the vessel’s\nmanagement company. Feedback should be provided, and formal agreement obtained to ensure the operation aligns with\nsafety protocols and company procedures.\nAll personnel involved must be familiar with the permit-to-work system and adhere to the defined safety requirements\nthroughout the operation.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":46,"source_page_end":46,"raw_source_text":"Are procedures in place for the control of hot work, are they incorporated in the safety management system\nand is there documented evidence of compliance? (M)\nGuide to Inspection\nPermits for hot work should be specific regarding the exact risks associated with the specific hot work, location, timing, and\nhazards.\nPermits to hot work should address dangers to all adjacent cargo or other flammable materials that may be exposed, as well\nas the necessity for additional protective covers.\nHot work means any work requiring the use of electric arc or gas welding equipment, cutting burner equipment or other forms\nof naked flame, as well as heating or spark generating tools, regardless of where it is carried out on board a ship. The safety\nmanagement system (SMS) on board should include adequate guidance on control of hot work and should be robust enough\nto ensure compliance. Absence of guidance should be regarded as prohibition, rather than approval.\nWhenever possible, a space such as a workshop where conditions are deemed safe, should be designated for hot work to be\nperformed and first consideration given to performing any hot work in that space.\n> Hot work performed outside that space should be subject to the following considerations.\nHot work outside the designated space:\n> The Master or designated safety officer should be responsible for deciding whether hot work is justified and whether it\ncan be conducted safely.\n> A permit-to-work system should be employed.\n> Hot work procedures should take account of national laws or regulations or other national safety and health rules.\n> A responsible officer, not involved in the hot work, should be designated to ensure that safe procedures are followed.\n> A written plan for the operation should be agreed by all who will have responsibilities in connection with the hot work.\n> The work area should be carefully prepared and isolated before hot work commences.\n> Fire safety precautions should be reviewed, including fire equipment preparations, setting a fire watch in adjacent\ncompartments and areas, and fire-extinguishing measures.\n> Isolation of the work area and fire precautions should be continued until the risk of fire no longer exists.\n(Principles for Hot Work on Board all Types of Ships, 2003)\nHot work in places other than the workshop should be the subject of a permit to work.\n(Code of Safe Working Practices for Merchant Seafarer’s, 2024 )\nHot Work Outside Designated Spaces\nWhen hot work is required outside designated spaces, it is essential to follow strict safety protocols to ensure the operation is\nconducted safely and in compliance with company procedures.\nA written plan for the hot work should be prepared and reviewed prior to commencement by a representative of the vessel’s\nmanagement company. Feedback should be provided, and formal agreement obtained to ensure the operation aligns with\nsafety protocols and company procedures.\nAll personnel involved must be familiar with the permit-to-work system and adhere to the defined safety requirements\nthroughout the operation.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}}]}$RISQQ21$::jsonb AS payload
),
qs AS (
  SELECT id AS question_set_id FROM public.risq_question_sets WHERE question_set_code = 'RISQ_3_2' LIMIT 1
),
input_rows AS (
  SELECT *
  FROM payload p
  CROSS JOIN LATERAL jsonb_to_recordset(p.payload->'questions') AS r(
    section_code text,
    section_number integer,
    section_letter text,
    section_title text,
    printed_question_no text,
    internal_question_no text,
    question_sort_key numeric,
    question_text text,
    guide_to_inspection text,
    answer_type text,
    answer_options jsonb,
    answer_options_inferred boolean,
    inspection_marker text,
    is_removed_question boolean,
    is_active boolean,
    guide_status text,
    source_page_start integer,
    source_page_end integer,
    raw_source_text text,
    metadata jsonb
  )
),
section_lookup AS (
  SELECT s.id AS section_id, s.question_set_id, s.section_code
  FROM public.risq_sections s
  JOIN qs ON qs.question_set_id = s.question_set_id
)
INSERT INTO public.risq_questions (
  question_set_id,
  section_id,
  section_code,
  section_number,
  section_letter,
  section_title,
  printed_question_no,
  internal_question_no,
  question_sort_key,
  question_text,
  guide_to_inspection,
  answer_type,
  answer_options,
  answer_options_inferred,
  inspection_marker,
  is_removed_question,
  is_active,
  guide_status,
  source_page_start,
  source_page_end,
  raw_source_text,
  source_hash,
  metadata,
  created_by,
  updated_by
)
SELECT
  qs.question_set_id,
  sl.section_id,
  i.section_code,
  i.section_number,
  i.section_letter,
  i.section_title,
  i.printed_question_no,
  i.internal_question_no,
  i.question_sort_key,
  i.question_text,
  i.guide_to_inspection,
  i.answer_type,
  i.answer_options,
  COALESCE(i.answer_options_inferred, false),
  COALESCE(i.inspection_marker, ''),
  COALESCE(i.is_removed_question, false),
  COALESCE(i.is_active, true),
  i.guide_status,
  i.source_page_start,
  i.source_page_end,
  i.raw_source_text,
  md5(COALESCE(i.question_text, '') || '|' || COALESCE(i.guide_to_inspection, '') || '|' || COALESCE(i.raw_source_text, '')),
  COALESCE(i.metadata, '{}'::jsonb),
  auth.uid(),
  auth.uid()
FROM input_rows i
CROSS JOIN qs
JOIN section_lookup sl
  ON sl.question_set_id = qs.question_set_id
 AND sl.section_code = i.section_code
ON CONFLICT (question_set_id, internal_question_no)
DO UPDATE SET
  section_id = EXCLUDED.section_id,
  section_code = EXCLUDED.section_code,
  section_number = EXCLUDED.section_number,
  section_letter = EXCLUDED.section_letter,
  section_title = EXCLUDED.section_title,
  printed_question_no = EXCLUDED.printed_question_no,
  question_sort_key = EXCLUDED.question_sort_key,
  question_text = EXCLUDED.question_text,
  guide_to_inspection = EXCLUDED.guide_to_inspection,
  answer_type = EXCLUDED.answer_type,
  answer_options = EXCLUDED.answer_options,
  answer_options_inferred = EXCLUDED.answer_options_inferred,
  inspection_marker = EXCLUDED.inspection_marker,
  is_removed_question = EXCLUDED.is_removed_question,
  is_active = EXCLUDED.is_active,
  guide_status = EXCLUDED.guide_status,
  source_page_start = EXCLUDED.source_page_start,
  source_page_end = EXCLUDED.source_page_end,
  raw_source_text = EXCLUDED.raw_source_text,
  source_hash = EXCLUDED.source_hash,
  metadata = EXCLUDED.metadata,
  updated_by = auth.uid();

COMMIT;

SELECT
  'RISQ question chunk 2/15 imported.' AS result,
  '03A.018' AS chunk_first_question,
  '04A.007' AS chunk_last_question,
  (SELECT COUNT(*) FROM public.risq_questions q JOIN public.risq_question_sets qs ON qs.id = q.question_set_id WHERE qs.question_set_code = 'RISQ_3_2') AS total_questions_imported_so_far;
